import React, { useState, useEffect } from 'react';
import { View } from './types';
import Sidebar from './components/Sidebar';
import Navbar from './components/Navbar';
import Dashboard from './pages/Dashboard';
import Properties from './pages/Properties';
import Tenants from './pages/Tenants';
import Financials from './pages/Financials';
import Maintenance from './pages/Maintenance';
import Communications from './pages/Communications';
import Login from './pages/Login';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>(View.LOGIN);
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  // Simple routing based on view state
  const renderView = () => {
    switch (currentView) {
      case View.DASHBOARD: return <Dashboard />;
      case View.PROPERTIES: return <Properties />;
      case View.TENANTS: return <Tenants />;
      case View.FINANCIALS: return <Financials />;
      case View.MAINTENANCE: return <Maintenance />;
      case View.COMMUNICATIONS: return <Communications />;
      case View.LOCATIONS: return <div className="p-8"><h2 className="text-2xl font-bold">Locations Map (Service Placeholder)</h2></div>;
      case View.RENTS: return <div className="p-8"><h2 className="text-2xl font-bold">Rents Management</h2></div>;
      case View.SALES: return <div className="p-8"><h2 className="text-2xl font-bold">Sales & Portfolios</h2></div>;
      default: return <Dashboard />;
    }
  };

  const handleLogin = () => {
    setIsAuthenticated(true);
    setCurrentView(View.DASHBOARD);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentView(View.LOGIN);
  };

  if (!isAuthenticated) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      <Sidebar currentView={currentView} setView={setCurrentView} />
      <div className="flex-1 flex flex-col min-w-0">
        <Navbar onLogout={handleLogout} />
        <main className="flex-1 overflow-y-auto">
          {renderView()}
        </main>
      </div>
    </div>
  );
};

export default App;

