import Login from './pages/Login';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>(View.LOGIN);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [userRole, setUserRole] = useState<UserRole | null>(null);

  // Simple routing based on view state
  const renderView = () => {
    switch (currentView) {
      case View.DASHBOARD: return <Dashboard role={userRole} />;
      case View.PROPERTIES: return <Properties />;
      case View.TENANTS: return <Tenants />;
      case View.FINANCIALS: return <Financials />;
      case View.MAINTENANCE: return <Maintenance />;
      case View.COMMUNICATIONS: return <Communications />;
      case View.LOCATIONS: return <div className="p-8"><h2 className="text-2xl font-bold">Locations Map</h2></div>;
      case View.RENTS: return <div className="p-8"><h2 className="text-2xl font-bold">Rents Management</h2></div>;
      case View.SALES: return <div className="p-8"><h2 className="text-2xl font-bold">Sales & Portfolios</h2></div>;
      default: return <Dashboard role={userRole} />;
    }
  };

  const handleLogin = (role: UserRole) => {
    setUserRole(role);
    setIsAuthenticated(true);
    setCurrentView(View.DASHBOARD);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setUserRole(null);
    setCurrentView(View.LOGIN);
  };

  if (!isAuthenticated) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      <Sidebar currentView={currentView} setView={setCurrentView} userRole={userRole} />
      <div className="flex-1 flex flex-col min-w-0">
        <Navbar onLogout={handleLogout} userRole={userRole} />
        <main className="flex-1 overflow-y-auto">
          {renderView()}
        </main>
      </div>
    </div>
  );
};

export default App;

