import React from 'react';
import { View, UserRole } from '../types';

interface SidebarProps {
  currentView: View;
  setView: (view: View) => void;
  userRole: UserRole | null;
}

const Sidebar: React.FC<SidebarProps> = ({ currentView, setView, userRole }) => {
  const isAdmin = userRole === UserRole.ADMIN;

  const navItems = [
    { id: View.DASHBOARD, label: 'Dashboard', icon: 'fa-chart-pie', roles: [UserRole.ADMIN, UserRole.USER] },
    { id: View.PROPERTIES, label: 'Properties', icon: 'fa-building', roles: [UserRole.ADMIN, UserRole.USER] },
    { id: View.LOCATIONS, label: 'Locations', icon: 'fa-map-location-dot', roles: [UserRole.ADMIN, UserRole.USER] },
    { id: View.TENANTS, label: 'Tenants', icon: 'fa-users', roles: [UserRole.ADMIN, UserRole.USER] },
    { id: View.MAINTENANCE, label: 'Maintenance', icon: 'fa-wrench', roles: [UserRole.ADMIN, UserRole.USER] },
    { id: View.COMMUNICATIONS, label: 'Communications', icon: 'fa-comment-dots', roles: [UserRole.ADMIN, UserRole.USER] },
    // Admin only items
    { id: View.FINANCIALS, label: 'Financials & Reports', icon: 'fa-file-contract', roles: [UserRole.ADMIN] },
    { id: View.SALES, label: 'Portfolio Sales', icon: 'fa-handshake', roles: [UserRole.ADMIN] },
    { id: View.RENTS, label: 'System Audit', icon: 'fa-file-invoice-dollar', roles: [UserRole.ADMIN] },
  ];

  const filteredNavItems = navItems.filter(item => userRole && item.roles.includes(userRole));

  return (
    <aside className="w-64 bg-slate-900 text-slate-300 flex flex-col shadow-xl z-20 hidden md:flex">
      <div className="p-6 flex items-center space-x-3">
        <div className="w-8 h-8 bg-indigo-500 rounded-lg flex items-center justify-center">
          <i className="fa-solid fa-home text-white"></i>
        </div>
        <span className="text-xl font-bold text-white tracking-tight">EliteEstate</span>
      </div>

      <nav className="flex-1 px-4 space-y-1 mt-4">
        {filteredNavItems.map((item) => (
          <button
            key={item.id}
            onClick={() => setView(item.id)}
            className={`w-full flex items-center space-x-3 px-3 py-3 rounded-xl transition-all duration-200 group ${
              currentView === item.id 
                ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20' 
                : 'hover:bg-slate-800 hover:text-white'
            }`}
          >
            <i className={`fa-solid ${item.icon} w-5 ${currentView === item.id ? 'text-white' : 'text-slate-400 group-hover:text-white'}`}></i>
            <span className="font-medium text-sm">{item.label}</span>
          </button>
        ))}
      </nav>

      <div className="p-4 border-t border-slate-800">
        <div className="bg-slate-800 rounded-xl p-4 flex items-center space-x-3">
          <div className="w-10 h-10 rounded-full bg-slate-700 flex items-center justify-center text-xs font-bold text-indigo-400">
            {isAdmin ? 'AD' : 'AG'}
          </div>
          <div>
            <p className="text-xs font-bold text-white uppercase truncate w-24">
              {isAdmin ? 'Full Admin' : 'Agent Access'}
            </p>
            <p className="text-[10px] text-slate-500 italic">ID: 88219-X</p>
          </div>
        </div>
      </div>
    </aside>
  );
};

