      });
    });

    // 2. Add Sales & Rents from Sales table
    sales.forEach(sale => {
      const property = properties.find(p => p.id === sale.propertyId);
      list.push({
        id: sale.id,
        date: sale.date,
        description: `${sale.transactionType}: ${property?.name || 'Property'}`,
        amount: sale.amount,
        type: 'Income',
        category: sale.transactionType,
        client: sale.clientName,
        source: sale.transactionType
      });
    });

