import React, { useState } from 'react';
import { View, UserRole } from './types';
import Sidebar from './components/Sidebar';
import Navbar from './components/Navbar';
import Dashboard from './pages/Dashboard';
import Properties from './pages/Properties';
import Tenants from './pages/Tenants';
import Financials from './pages/Financials';
import Maintenance from './pages/Maintenance';
import Communications from './pages/Communications';
import Sales from './pages/Sales';
import Locations from './pages/Locations';
import Login from './pages/Login';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>(View.LOGIN);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [userRole, setUserRole] = useState<UserRole | null>(null);

  // Simple routing based on view state
  const renderView = () => {
    switch (currentView) {
      case View.DASHBOARD: return <Dashboard role={userRole} />;
      case View.PROPERTIES: return <Properties />;
      case View.TENANTS: return <Tenants />;
      case View.FINANCIALS: return <Financials />;
      case View.MAINTENANCE: return <Maintenance />;
      case View.COMMUNICATIONS: return <Communications />;
      case View.SALES: return <Sales />;
      case View.LOCATIONS: return <Locations />;
      case View.RENTS: return <div className="p-8"><h2 className="text-2xl font-bold">Rents Management</h2></div>;
      default: return <Dashboard role={userRole} />;
    }
  };

  const handleLogin = (role: UserRole) => {
    setUserRole(role);
    setIsAuthenticated(true);
    setCurrentView(View.DASHBOARD);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setUserRole(null);
    setCurrentView(View.LOGIN);
  };

  // Login view is rendered separately to ensure zero style leakage between login and dashboard
  if (!isAuthenticated) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden text-slate-900 font-sans selection:bg-indigo-100 selection:text-indigo-900">
      <Sidebar currentView={currentView} setView={setCurrentView} userRole={userRole} />
      <div className="flex-1 flex flex-col min-w-0 bg-slate-50">
        <Navbar onLogout={handleLogout} userRole={userRole} />
        <main className="flex-1 overflow-y-auto custom-scrollbar">
          {renderView()}
        </main>
      </div>
    </div>
  );
};

export default App;

export enum View {
  LOGIN = 'login',
  DASHBOARD = 'dashboard',
  PROPERTIES = 'properties',
  LOCATIONS = 'locations',
  RENTS = 'rents',
  TENANTS = 'tenants',
  SALES = 'sales',
  FINANCIALS = 'financials',
  MAINTENANCE = 'maintenance',
  COMMUNICATIONS = 'communications'
}

export enum UserRole {
  ADMIN = 'admin',
  USER = 'user'
}

export interface Property {
  id: string;
  name: string;
  address: string;
  type: 'Apartment' | 'House' | 'Hotel' | 'Commercial';
  status: 'Occupied' | 'Vacant' | 'Under Maintenance';
  price: number;
  rooms: number;
  kitchens: number;
  bathrooms: number;
  image: string;
}

export interface Tenant {
  id: string;
  name: string;
  propertyId: string;
  unit: string;
  email: string;
  phone: string;
  leaseStart: string;
  leaseEnd: string;
  status: 'Active' | 'Ending Soon' | 'Past Due';
}

export interface Sale {
  id: string;
  propertyId: string;
  clientName: string;
  amount: number;
  date: string;
  transactionType: 'Sale' | 'Rent';
  status: 'Completed' | 'Pending' | 'Cancelled';
}

export interface RentRecord {
  id: string;
  propertyId: string;
  amount: number;
  dueDate: string;
