                  className="block w-full pl-10 pr-10 py-3 bg-slate-50 border-2 border-slate-50 rounded-xl text-xs font-semibold focus:outline-none focus:ring-0 focus:border-teal-500/50 focus:bg-white transition-all placeholder:text-slate-300"
                  placeholder="••••••••"
                  required
                />
                <button 
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute inset-y-0 right-0 pr-4 flex items-center text-slate-400 hover:text-teal-600 transition-colors"
                >
                  <i className={`fa-solid ${showPassword ? 'fa-eye-slash' : 'fa-eye'} text-xs`}></i>
                </button>
              </div>
            </div>

            <div className="flex items-center justify-between px-1">
              <label className="flex items-center gap-2 cursor-pointer group">
                <input type="checkbox" className="w-4 h-4 rounded text-teal-600 border-slate-200 focus:ring-teal-500 focus:ring-offset-0 transition-all cursor-pointer" />
                <span className="text-[10px] text-slate-500 font-bold group-hover:text-slate-700 transition-colors">I xasuuso</span>
              </label>
              <button type="button" className="text-[10px] font-black text-teal-600 hover:text-teal-700 hover:underline">Ilaaway?</button>
            </div>

            <button
              type="submit"
              disabled={isLoading}
              className="w-full py-4 bg-teal-600 text-white rounded-xl font-black text-xs shadow-lg shadow-teal-600/20 hover:bg-teal-700 active:scale-[0.98] transition-all flex items-center justify-center gap-2 mt-2 group"
            >
              {isLoading ? (
                <i className="fa-solid fa-circle-notch fa-spin text-sm"></i>
              ) : (
                <>
                  <span>GALI DASHBOARD</span>
                  <i className="fa-solid fa-arrow-right-long group-hover:translate-x-1 transition-transform"></i>
                </>
              )}
            </button>
          </form>

          <p className="text-center mt-6 text-[9px] text-slate-400 font-black uppercase tracking-widest">
            EliteEstate Pro &copy; 2024
          </p>
        </div>
      </div>
    </div>
  );
};

