      setFormData({
        clientName: '',
        description: '',
        totalAmount: 0,
        paidAmount: 0,
        category: 'Income',
        date: new Date().toISOString().split('T')[0]
      });
    }
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setEditingRecord(null);
  };

