    return {
      paidTotal: records.filter(r => r.status === 'Paid').reduce((acc, curr) => acc + curr.paidAmount, 0),
      debtTotal: records.filter(r => r.status === 'Debt').reduce((acc, curr) => acc + (curr.totalAmount - curr.paidAmount), 0),
      partialTotalPaid: records.filter(r => r.status === 'Partial').reduce((acc, curr) => acc + curr.paidAmount, 0),
      partialTotalRemaining: records.filter(r => r.status === 'Partial').reduce((acc, curr) => acc + (curr.totalAmount - curr.paidAmount), 0),
    };
