          <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform">
             <i className="fa-solid fa-circle-check text-4xl text-emerald-600"></i>
          </div>
          <p className="text-[10px] font-black text-emerald-700 uppercase tracking-[0.2em] mb-1">Lacagta la bixiyay (Paid)</p>
          <h3 className="text-2xl font-black text-emerald-600">${stats.paidTotal.toLocaleString()}</h3>
          <p className="text-[10px] font-bold text-emerald-800/60 mt-2 uppercase">Dakhli dhameystiran</p>
        </div>

        <div className="bg-rose-50 border border-rose-100 p-6 rounded-[2rem] shadow-sm relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform">
             <i className="fa-solid fa-hand-holding-dollar text-4xl text-rose-600"></i>
          </div>
          <p className="text-[10px] font-black text-rose-700 uppercase tracking-[0.2em] mb-1">Kuwa Daynta ah (Debt)</p>
          <h3 className="text-2xl font-black text-rose-600">${stats.debtTotal.toLocaleString()}</h3>
          <p className="text-[10px] font-bold text-rose-800/60 mt-2 uppercase">Wali lama bixin</p>
        </div>

        <div className="bg-amber-50 border border-amber-100 p-6 rounded-[2rem] shadow-sm relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform">
             <i className="fa-solid fa-pie-chart text-4xl text-amber-600"></i>
          </div>
          <p className="text-[10px] font-black text-amber-700 uppercase tracking-[0.2em] mb-1">Qaar la bixiyay (Partial)</p>
          <h3 className="text-2xl font-black text-amber-600">${stats.partialTotalPaid.toLocaleString()}</h3>
          <p className="text-[10px] font-bold text-amber-800/60 mt-1 uppercase">Dhiman: ${stats.partialTotalRemaining.toLocaleString()}</p>
