          </div>
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1">Dakhliga Guud (Total)</p>
          <h3 className="text-2xl font-black text-white">${(stats.paidTotal + stats.partialTotalPaid).toLocaleString()}</h3>
