  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  const handleSend = async (customText?: string) => {
    const textToSend = customText || input;
    if (!textToSend.trim()) return;

    const userMsg: Message = {
      role: 'user',
      text: textToSend,
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      // Context for the AI to understand our current system state
      const context = `
        Current System Data Summary:
        - Total Properties: ${properties.length}
        - Vacant Properties: ${properties.filter(p => p.status === 'Vacant').length}
        - Occupied Properties: ${properties.filter(p => p.status === 'Occupied').length}
        - Total Tenants: ${tenants.length}
        - Maintenance Requests: ${maintenanceRequests.length} (${maintenanceRequests.filter(r => r.status !== 'Completed').length} active)
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: textToSend,
        config: {
          systemInstruction: `You are EliteEstate AI, a professional real estate assistant for a management system in Somalia. 
          Use the following context about the current database: ${context}. 
          Respond in Somali primarily, but keep professional terms if needed. 
          Be helpful, concise, and professional. 
          If asked to draft a notice, make it formal.`,
        },
      });

      const botMsg: Message = {
        role: 'bot',
        text: response.text || "Waan ka xumahay, hadda ma jawaabi karo. Fadlan mar kale isku day.",
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
      };

      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
      console.error("AI Error:", error);
      setMessages(prev => [...prev, {
        role: 'bot',
        text: "Cillad farsamo ayaa dhacday. Fadlan hubi xiriirkaaga internetka.",
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
      }]);
    } finally {
      setIsTyping(false);
    }
  };

  const quickActions = [
    { label: "Guryaha Bannaan", prompt: "Immisa guri ayaa hadda bannaan? Ii sheeg magacyadooda." },
    { label: "Warbixin Dayactir", prompt: "Iii soo koob dhammaan codsiyada dayactirka ee hadda socda." },
    { label: "Ogeysiis Kiro", prompt: "Ii qor ogeysiis rasmi ah oo loo dirayo macmiilka kirada ku daahay." }
  ];

  return (
    <div className="h-[calc(100vh-64px)] flex flex-col bg-slate-50 font-sans">
      {/* Header */}
      <div className="bg-white border-b border-slate-200 px-8 py-4 flex items-center justify-between shadow-sm z-10">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center shadow-lg shadow-indigo-200 animate-pulse">
            <i className="fa-solid fa-robot text-white text-xl"></i>
          </div>
          <div>
            <h2 className="text-lg font-black text-slate-900 leading-tight">EliteEstate AI</h2>
            <div className="flex items-center gap-1.5">
              <span className="w-2 h-2 bg-emerald-500 rounded-full"></span>
              <span className="text-[10px] font-black text-emerald-500 uppercase tracking-widest">Active Assistant</span>
            </div>
          </div>
        </div>
        <div className="flex gap-2">
           <button className="p-2.5 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all border border-transparent hover:border-indigo-100">
             <i className="fa-solid fa-ellipsis-vertical"></i>
           </button>
        </div>
      </div>

      {/* Chat History */}
      <div 
        ref={scrollRef}
        className="flex-1 overflow-y-auto p-6 md:p-10 space-y-8 scroll-smooth"
      >
        <div className="max-w-4xl mx-auto space-y-8">
          {messages.map((msg, idx) => (
            <div 
              key={idx} 
              className={`flex items-start gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : ''} animate-in fade-in slide-in-from-bottom-4 duration-500`}
            >
              <div className={`w-10 h-10 rounded-2xl flex items-center justify-center flex-shrink-0 shadow-sm border ${
                msg.role === 'user' 
                ? 'bg-slate-900 text-white border-slate-800' 
                : 'bg-indigo-100 text-indigo-600 border-indigo-200'
              }`}>
                <i className={`fa-solid ${msg.role === 'user' ? 'fa-user' : 'fa-robot'} text-xs`}></i>
              </div>

              <div className={`max-w-[80%] space-y-1 ${msg.role === 'user' ? 'text-right' : 'text-left'}`}>
                <div className={`p-5 rounded-[2rem] shadow-sm text-sm font-medium leading-relaxed ${
                  msg.role === 'user' 
                  ? 'bg-indigo-600 text-white rounded-tr-none' 
                  : 'bg-white text-slate-800 rounded-tl-none border border-slate-100'
                }`}>
                  {msg.text}
                </div>
                <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest px-2">
                  {msg.timestamp}
                </p>
              </div>
            </div>
          ))}

          {isTyping && (
            <div className="flex items-start gap-4 animate-in fade-in duration-300">
              <div className="w-10 h-10 rounded-2xl bg-indigo-100 text-indigo-600 flex items-center justify-center border border-indigo-200">
                <i className="fa-solid fa-robot text-xs"></i>
              </div>
              <div className="bg-white p-5 rounded-[2rem] rounded-tl-none border border-slate-100 shadow-sm">
                <div className="flex gap-1">
                  <span className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce"></span>
                  <span className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:0.2s]"></span>
                  <span className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:0.4s]"></span>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Input Area */}
      <div className="bg-white border-t border-slate-200 p-6 md:p-8">
        <div className="max-w-4xl mx-auto space-y-6">
          {/* Quick Action Suggestions */}
          <div className="flex flex-wrap gap-2">
            {quickActions.map((action, i) => (
              <button 
                key={i}
                onClick={() => handleSend(action.prompt)}
                className="px-4 py-2 bg-slate-50 border border-slate-200 hover:border-indigo-300 hover:bg-indigo-50 text-[10px] font-black text-slate-500 hover:text-indigo-600 rounded-full transition-all uppercase tracking-wider shadow-sm"
              >
                {action.label}
              </button>
            ))}
          </div>

          {/* Form */}
          <form 
            onSubmit={(e) => { e.preventDefault(); handleSend(); }}
            className="relative flex items-center gap-4"
          >
            <div className="flex-1 relative group">
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                placeholder="Wax i weydii..."
                className="w-full pl-6 pr-14 py-5 bg-slate-50 border-2 border-slate-50 rounded-[2.5rem] text-sm font-semibold focus:outline-none focus:border-indigo-500/50 focus:bg-white transition-all shadow-inner group-hover:bg-slate-100"
              />
              <div className="absolute right-4 top-1/2 -translate-y-1/2 flex items-center gap-2">
                 <button type="button" className="text-slate-300 hover:text-indigo-500 transition-colors p-2">
                   <i className="fa-solid fa-paperclip"></i>
                 </button>
              </div>
            </div>

            <button
              type="submit"
              disabled={!input.trim() || isTyping}
              className={`w-16 h-16 rounded-[2rem] flex items-center justify-center transition-all shadow-xl active:scale-95 ${
                !input.trim() || isTyping 
                ? 'bg-slate-100 text-slate-300 cursor-not-allowed' 
                : 'bg-indigo-600 text-white shadow-indigo-500/30 hover:bg-indigo-700'
              }`}
            >
              <i className={`fa-solid ${isTyping ? 'fa-circle-notch fa-spin' : 'fa-paper-plane'} text-lg`}></i>
            </button>
          </form>

          <p className="text-center text-[9px] font-bold text-slate-300 uppercase tracking-[0.3em]">
            EliteEstate AI utilizes Gemini Flash 3.0 for enhanced property analysis
          </p>
        </div>
      </div>
    </div>
  );
};

export default Communications;

import React from 'react';
