import React, { useState } from 'react';
import { properties as initialProperties } from '../mockData';
import { Property } from '../types';

const Properties: React.FC = () => {
  const [propertyList, setPropertyList] = useState<Property[]>(initialProperties);
  const [filter, setFilter] = useState('All');
  const [typeFilter, setTypeFilter] = useState('All');

  // Modal states
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingProperty, setEditingProperty] = useState<Property | null>(null);

  // Form states
  const [formData, setFormData] = useState<Partial<Property>>({
    name: '',
    address: '',
    type: 'Apartment',
    status: 'Vacant',
    price: 0,
    rooms: 1,
    kitchens: 1,
    bathrooms: 1,
    image: 'https://images.unsplash.com/photo-1560518883-ce09059eeffa?auto=format&fit=crop&w=800&q=80'
  });

  const filteredProperties = propertyList.filter(p => {
    const statusMatch = filter === 'All' || p.status === filter;
    const typeMatch = typeFilter === 'All' || p.type === typeFilter;
    return statusMatch && typeMatch;
  });

  const handleOpenModal = (property?: Property) => {
    if (property) {
      setEditingProperty(property);
      setFormData(property);
    } else {
      setEditingProperty(null);
      setFormData({
        name: '',
        address: '',
        type: 'Apartment',
        status: 'Vacant',
        price: 0,
        rooms: 1,
        kitchens: 1,
        bathrooms: 1,
        image: 'https://images.unsplash.com/photo-1560518883-ce09059eeffa?auto=format&fit=crop&w=800&q=80'
      });
    }
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setEditingProperty(null);
  };

  const handleDelete = (id: string) => {
    if (window.confirm('Ma hubtaa inaad tirtirto gurigan?')) {
      setPropertyList(prev => prev.filter(p => p.id !== id));
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingProperty) {
      setPropertyList(prev => prev.map(p => p.id === editingProperty.id ? { ...p, ...formData } as Property : p));
    } else {
      const newProperty: Property = {
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
      } as Property;
      setPropertyList(prev => [newProperty, ...prev]);
    }
    handleCloseModal();
  };

  const getStatusBadge = (status: string) => {
    switch (status) {
      case 'Occupied':
        return <span className="px-3 py-1 bg-rose-500 text-white text-[10px] font-black uppercase tracking-widest rounded-full shadow-lg">La Deggan Yahay</span>;
      case 'Vacant':
        return <span className="px-3 py-1 bg-emerald-500 text-white text-[10px] font-black uppercase tracking-widest rounded-full shadow-lg">Waa Bannaan Yahay</span>;
      default:
        return <span className="px-3 py-1 bg-amber-500 text-white text-[10px] font-black uppercase tracking-widest rounded-full shadow-lg">Dayactir</span>;
    }
  };

  const getTypeIcon = (type: string) => {
    switch (type) {
      case 'Apartment': return 'fa-building-user';
      case 'House': return 'fa-house-chimney';
      case 'Hotel': return 'fa-hotel';
      case 'Commercial': return 'fa-shop';
      default: return 'fa-building';
    }
  };

  return (
    <div className="p-8 space-y-8 animate-in fade-in duration-700 relative">
      {/* Header & Controls */}
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">Guryaha & Ganacsiga</h1>
          <p className="text-slate-500 font-medium mt-1">Maamul dhammaan macluumaadka guryahaaga.</p>
        </div>

        <div className="flex flex-wrap gap-3">
          <div className="flex bg-white p-1 rounded-2xl border border-slate-200 shadow-sm">
            {['All', 'Occupied', 'Vacant'].map(tab => (
              <button
                key={tab}
                onClick={() => setFilter(tab)}
                className={`px-4 py-2 rounded-xl text-xs font-bold transition-all ${
                  filter === tab ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-800'
                }`}
              >
                {tab === 'All' ? 'Dhammaan' : tab === 'Occupied' ? 'Lagu Jiro' : 'Bannaan'}
              </button>
            ))}
          </div>

          <select 
            value={typeFilter}
            onChange={(e) => setTypeFilter(e.target.value)}
            className="bg-white border border-slate-200 rounded-2xl px-4 py-2 text-xs font-bold text-slate-700 focus:ring-2 focus:ring-indigo-500 outline-none shadow-sm cursor-pointer"
          >
            <option value="All">Dhammaan Noocyada</option>
            <option value="Apartment">Apartment</option>
            <option value="House">House</option>
            <option value="Hotel">Hotel</option>
            <option value="Commercial">Ganacsi</option>
          </select>

          <button 
            onClick={() => handleOpenModal()}
            className="px-6 py-2 bg-indigo-600 text-white rounded-2xl text-xs font-black uppercase tracking-widest hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-600/20 active:scale-95"
          >
            <i className="fa-solid fa-plus mr-2"></i> Guri Cusub
          </button>
        </div>
      </div>

      {/* Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {filteredProperties.map((property: Property) => (
          <div key={property.id} className="bg-white rounded-[2.5rem] overflow-hidden shadow-sm border border-slate-100 hover:shadow-2xl hover:border-indigo-100 transition-all duration-500 group">
            {/* Image Container */}
            <div className="relative h-64 overflow-hidden">
              <img 
                src={property.image} 
                alt={property.name} 
                className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" 
              />
              <div className="absolute inset-0 bg-gradient-to-t from-slate-900/60 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-500"></div>

              <div className="absolute top-5 left-5">
                {getStatusBadge(property.status)}
              </div>

              <div className="absolute bottom-5 left-5 right-5 flex justify-between items-end transform translate-y-4 opacity-0 group-hover:translate-y-0 group-hover:opacity-100 transition-all duration-500">
                <div className="bg-white/90 backdrop-blur-md px-3 py-1.5 rounded-xl flex items-center gap-2">
                  <i className={`fa-solid ${getTypeIcon(property.type)} text-indigo-600`}></i>
                  <span className="text-[10px] font-black uppercase tracking-widest text-slate-900">{property.type}</span>
                </div>
              </div>
            </div>

            {/* Content */}
            <div className="p-8">
              <div className="flex justify-between items-start mb-2">
                <h3 className="text-xl font-black text-slate-900 group-hover:text-indigo-600 transition-colors">{property.name}</h3>
                <div className="text-right">
                  <span className="text-2xl font-black text-indigo-600">${property.price}</span>
                  <span className="text-[10px] font-bold text-slate-400 block uppercase">Bishii / Rent</span>
                </div>
              </div>

              <p className="text-slate-500 text-sm flex items-center font-medium mb-6">
                <i className="fa-solid fa-location-dot mr-2 text-rose-500"></i> {property.address}
              </p>

              {/* Specs Grid */}
              <div className="grid grid-cols-3 gap-3 mb-8">
                <div className="bg-slate-50 rounded-2xl p-4 flex flex-col items-center justify-center border border-slate-100 group-hover:bg-indigo-50 group-hover:border-indigo-100 transition-colors">
                  <i className="fa-solid fa-bed text-slate-400 mb-2 group-hover:text-indigo-500"></i>
                  <span className="text-sm font-black text-slate-900">{property.rooms}</span>
                  <span className="text-[9px] font-bold text-slate-400 uppercase">Qol</span>
                </div>
                <div className="bg-slate-50 rounded-2xl p-4 flex flex-col items-center justify-center border border-slate-100 group-hover:bg-indigo-50 group-hover:border-indigo-100 transition-colors">
                  <i className="fa-solid fa-kitchen-set text-slate-400 mb-2 group-hover:text-indigo-500"></i>
                  <span className="text-sm font-black text-slate-900">{property.kitchens}</span>
                  <span className="text-[9px] font-bold text-slate-400 uppercase">Jiko</span>
                </div>
                <div className="bg-slate-50 rounded-2xl p-4 flex flex-col items-center justify-center border border-slate-100 group-hover:bg-indigo-50 group-hover:border-indigo-100 transition-colors">
                  <i className="fa-solid fa-sink text-slate-400 mb-2 group-hover:text-indigo-500"></i>
                  <span className="text-sm font-black text-slate-900">{property.bathrooms}</span>
                  <span className="text-[9px] font-bold text-slate-400 uppercase">Sooli</span>
                </div>
              </div>

              {/* Actions */}
              <div className="flex gap-3">
                <button 
                  onClick={() => handleOpenModal(property)}
                  className="flex-1 py-4 bg-slate-900 text-white rounded-2xl text-xs font-black uppercase tracking-widest hover:bg-indigo-600 transition-all active:scale-95 shadow-xl shadow-slate-200 flex items-center justify-center gap-2"
                >
                  <i className="fa-solid fa-pen-to-square"></i>
                  Bedel (Edit)
                </button>
                <button 
                  onClick={() => handleDelete(property.id)}
                  className="w-14 h-14 flex items-center justify-center bg-slate-100 text-slate-500 rounded-2xl hover:bg-rose-50 hover:text-rose-500 transition-all border border-transparent hover:border-rose-100"
                >
                  <i className="fa-solid fa-trash-can"></i>
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Modal - Add/Edit Form */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={handleCloseModal}></div>
          <div className="bg-white rounded-[2.5rem] w-full max-w-2xl relative z-10 shadow-2xl animate-in zoom-in duration-300 overflow-hidden border-4 border-blue-600 ring-4 ring-blue-600/20">
            <div className="p-8 border-b border-slate-100 flex justify-between items-center">
              <h2 className="text-2xl font-black text-slate-900 tracking-tight">
                {editingProperty ? 'Bedel Guriga' : 'Kudar Guri Cusub'}
              </h2>
              <button onClick={handleCloseModal} className="w-10 h-10 rounded-full hover:bg-slate-100 flex items-center justify-center text-slate-400 transition-colors">
                <i className="fa-solid fa-xmark text-xl"></i>
              </button>
            </div>
            <form onSubmit={handleSubmit} className="p-8 overflow-y-auto max-h-[70vh]">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Magaca Guriga</label>
                  <input
                    type="text"
                    required
                    value={formData.name}
                    onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                    className="w-full px-5 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl text-sm font-semibold focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                    placeholder="Tusaale: Hilaac Apartment"
                  />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Qiimaha (Bishii)</label>
                  <input
                    type="number"
                    required
