            <p className="text-2xl font-black text-slate-900">${filteredRecords.reduce((acc, r) => acc + r.paidAmount, 0).toLocaleString()}</p>
          </div>
        </div>
      </div>

      {/* Modal Form */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
