                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nooca (Category)</label>
                  <select
                    value={formData.category}
                    onChange={(e) => setFormData({ ...formData, category: e.target.value as any })}
                    className="w-full px-5 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl text-sm font-semibold focus:ring-2 focus:ring-teal-500 outline-none transition-all"
                  >
                    <option value="Income">Dakhli (Income)</option>
                    <option value="Expense">Kharash (Expense)</option>
                  </select>
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Taariikhda</label>
                  <input
                    type="date"
                    required
                    value={formData.date}
                    onChange={(e) => setFormData({ ...formData, date: e.target.value })}
                    className="w-full px-5 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl text-sm font-semibold focus:ring-2 focus:ring-teal-500 outline-none transition-all"
                  />
                </div>
              </div>

              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Magaca Macmiilka / Client</label>
                <input
                  type="text"
                  required
                  value={formData.clientName}
                  onChange={(e) => setFormData({ ...formData, clientName: e.target.value })}
                  className="w-full px-5 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl text-sm font-semibold focus:ring-2 focus:ring-teal-500 outline-none transition-all"
                  placeholder="Halkan ku qor magaca..."
                />
              </div>

              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Faahfaahin (Description)</label>
                <textarea
                  required
                  rows={2}
                  value={formData.description}
                  onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                  className="w-full px-5 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl text-sm font-semibold focus:ring-2 focus:ring-teal-500 outline-none transition-all resize-none"
                  placeholder="Maxay tahay lacagtan?"
                />
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Lacagta Guud (Total Amount)</label>
                  <input
                    type="number"
                    required
                    value={formData.totalAmount}
                    onChange={(e) => setFormData({ ...formData, totalAmount: Number(e.target.value) })}
                    className="w-full px-5 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl text-sm font-semibold focus:ring-2 focus:ring-teal-500 outline-none transition-all"
                    placeholder="$0.00"
                  />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Lacagta la bixiyay (Paid Amount)</label>
                  <input
                    type="number"
                    required
                    value={formData.paidAmount}
                    onChange={(e) => setFormData({ ...formData, paidAmount: Number(e.target.value) })}
                    className="w-full px-5 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl text-sm font-semibold focus:ring-2 focus:ring-teal-500 outline-none transition-all"
                    placeholder="$0.00"
                  />
                </div>
              </div>

              <div className="p-4 bg-teal-50 rounded-2xl flex items-center justify-between">
                <span className="text-[10px] font-black text-teal-700 uppercase">Xaaladda hadda:</span>
                <span className={`text-[10px] font-black uppercase px-2 py-1 rounded-lg ${
                  formData.paidAmount === formData.totalAmount ? 'bg-emerald-500 text-white' :
                  formData.paidAmount === 0 ? 'bg-rose-500 text-white' : 'bg-amber-500 text-white'
                }`}>
                  {formData.paidAmount === formData.totalAmount ? 'Dhameystiran (Paid)' :
                   formData.paidAmount === 0 ? 'Dayn (Debt)' : 'Qabyo (Partial)'}
                </span>
              </div>

              <button
                type="submit"
                className="w-full py-5 bg-teal-600 text-white rounded-2xl font-black text-sm shadow-xl shadow-teal-600/20 hover:bg-teal-700 transition-all flex items-center justify-center gap-3 mt-4 active:scale-[0.98]"
              >
                <i className="fa-solid fa-check-circle"></i>
                {editingRecord ? 'KEYDI ISBADALKA' : 'DHAMAYSTIR DIWAANKA'}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

