import React, { useState } from 'react';
import { maintenanceRequests as initialRequests, properties } from '../mockData';
import { MaintenanceRequest, Property } from '../types';

const Maintenance: React.FC = () => {
  const [requestList, setRequestList] = useState<MaintenanceRequest[]>(initialRequests);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingRequest, setEditingRequest] = useState<MaintenanceRequest | null>(null);

  // Form state
  const [formData, setFormData] = useState<Partial<MaintenanceRequest>>({
    propertyName: properties[0]?.name || '',
    tenantName: '',
    issue: '',
    priority: 'Medium',
    status: 'New',
    date: new Date().toISOString().split('T')[0]
  });

  const handleOpenModal = (request?: MaintenanceRequest) => {
    if (request) {
      setEditingRequest(request);
      setFormData(request);
    } else {
      setEditingRequest(null);
      setFormData({
        propertyName: properties[0]?.name || '',
        tenantName: '',
        issue: '',
        priority: 'Medium',
        status: 'New',
        date: new Date().toISOString().split('T')[0]
      });
    }
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setEditingRequest(null);
  };

  const handleDelete = (id: string) => {
    if (window.confirm('Ma hubtaa inaad tirtirto codsigan dayactirka ah?')) {
      setRequestList(prev => prev.filter(r => r.id !== id));
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingRequest) {
      setRequestList(prev => prev.map(r => r.id === editingRequest.id ? { ...r, ...formData } as MaintenanceRequest : r));
    } else {
      const newRequest: MaintenanceRequest = {
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
      } as MaintenanceRequest;
      setRequestList(prev => [newRequest, ...prev]);
    }
    handleCloseModal();
  };

  const getStatusLabel = (status: string) => {
    switch (status) {
      case 'New': return 'Wali lama bilaabin';
      case 'In Progress': return 'Shaqa baa socota';
      case 'Completed': return 'Waa la dhameeyay';
      default: return status;
    }
  };

  const getPriorityColor = (priority: string) => {
    switch (priority) {
      case 'Urgent': return 'bg-rose-100 text-rose-600 border-rose-200';
      case 'High': return 'bg-amber-100 text-amber-600 border-amber-200';
      case 'Medium': return 'bg-blue-100 text-blue-600 border-blue-200';
      default: return 'bg-slate-100 text-slate-500 border-slate-200';
    }
  };

  const statuses = [
    { key: 'New', label: 'Wali lakama shaqayn', color: 'bg-slate-100' },
    { key: 'In Progress', label: 'Shaqa kusocta', color: 'bg-teal-50' },
    { key: 'Completed', label: 'Waa la dhameyay', color: 'bg-emerald-50' }
  ];

  return (
    <div className="p-8 space-y-8 animate-in fade-in duration-700">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">Dayactirka (Maintenance)</h1>
          <p className="text-slate-500 font-medium">Maamul oo la soco codsiyada dayactirka guryaha.</p>
        </div>
        <button 
          onClick={() => handleOpenModal()}
          className="px-6 py-3 bg-teal-600 text-white rounded-2xl text-xs font-black uppercase tracking-widest hover:bg-teal-700 transition-all shadow-lg shadow-teal-600/20 active:scale-95 flex items-center gap-2"
        >
          <i className="fa-solid fa-screwdriver-wrench"></i>
          Codsiga Dayactirka (Add Request)
        </button>
      </div>

      {/* Maintenance Boards */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {statuses.map(statusObj => (
          <div key={statusObj.key} className={`${statusObj.color}/40 p-6 rounded-[2.5rem] border border-slate-100 min-h-[600px] flex flex-col`}>
            <div className="flex items-center justify-between mb-6 px-2">
              <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest flex items-center gap-2">
                <span className={`w-2 h-2 rounded-full ${statusObj.key === 'Completed' ? 'bg-emerald-500' : statusObj.key === 'In Progress' ? 'bg-teal-500' : 'bg-slate-400'}`}></span>
                {statusObj.label}
              </h3>
              <span className="bg-white/80 backdrop-blur px-3 py-1 rounded-full text-[10px] font-black text-slate-500 shadow-sm border border-slate-100">
                {requestList.filter(r => r.status === statusObj.key).length}
              </span>
            </div>

            <div className="space-y-4 flex-1">
              {requestList
                .filter(r => r.status === statusObj.key)
                .map(request => (
                  <div key={request.id} className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 hover:shadow-xl hover:border-teal-100 transition-all group relative cursor-default">
                    <div className="flex items-center justify-between mb-4">
                      <span className={`text-[9px] font-black px-2.5 py-1 rounded-lg uppercase tracking-wider border ${getPriorityColor(request.priority)}`}>
                        {request.priority}
                      </span>
                      <span className="text-[10px] text-slate-400 font-bold">{request.date}</span>
                    </div>

                    <h4 className="font-black text-slate-900 mb-1 group-hover:text-teal-600 transition-colors leading-tight">{request.issue}</h4>
                    <p className="text-xs text-slate-500 font-medium mb-4 flex items-center">
                      <i className="fa-solid fa-building mr-1.5 opacity-40"></i> {request.propertyName}
                    </p>

                    <div className="pt-4 border-t border-slate-50 flex items-center justify-between">
                      <div className="flex items-center gap-2">
                        <div className="w-6 h-6 rounded-full bg-slate-100 text-slate-400 flex items-center justify-center text-[10px] font-black">
                          {request.tenantName.charAt(0) || 'U'}
                        </div>
                        <span className="text-[10px] font-bold text-slate-400 truncate w-24">{request.tenantName || 'Macmiil'}</span>
                      </div>

                      <div className="flex gap-1.5 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button 
                          onClick={() => handleOpenModal(request)}
                          className="w-8 h-8 flex items-center justify-center bg-teal-50 text-teal-600 rounded-lg hover:bg-teal-600 hover:text-white transition-all"
                          title="Edit"
                        >
                          <i className="fa-solid fa-pen text-[10px]"></i>
                        </button>
                        <button 
                          onClick={() => handleDelete(request.id)}
                          className="w-8 h-8 flex items-center justify-center bg-rose-50 text-rose-500 rounded-lg hover:bg-rose-500 hover:text-white transition-all"
                          title="Delete"
                        >
                          <i className="fa-solid fa-trash text-[10px]"></i>
                        </button>
                      </div>
                    </div>
                  </div>
                ))}

                {requestList.filter(r => r.status === statusObj.key).length === 0 && (
                  <div className="flex flex-col items-center justify-center py-12 border-2 border-dashed border-slate-200 rounded-[2rem] opacity-40">
                    <i className="fa-solid fa-clipboard-list text-2xl mb-2"></i>
                    <p className="text-[10px] font-black uppercase tracking-widest">Ma jiraan codsiyo</p>
                  </div>
                )}
            </div>
          </div>
        ))}
      </div>

      {/* Modal - Add/Edit Form */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={handleCloseModal}></div>
          <div className="bg-white rounded-[2.5rem] w-full max-w-xl relative z-10 shadow-2xl animate-in zoom-in duration-300 overflow-hidden border border-teal-500">
            <div className="p-8 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
              <h2 className="text-2xl font-black text-slate-900 tracking-tight">
                {editingRequest ? 'Bedel Codsiga' : 'Codsiga Dayactir Cusub'}
              </h2>
              <button onClick={handleCloseModal} className="w-10 h-10 rounded-full hover:bg-white flex items-center justify-center text-slate-400 transition-colors shadow-sm">
                <i className="fa-solid fa-xmark text-xl"></i>
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-6">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Dooro Dhismaha (Select Building)</label>
                <select
                  required
                  value={formData.propertyName}
                  onChange={(e) => setFormData({ ...formData, propertyName: e.target.value })}
                  className="w-full px-5 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl text-sm font-semibold focus:ring-2 focus:ring-teal-500 outline-none transition-all"
                >
                  {properties.map(p => (
                    <option key={p.id} value={p.name}>{p.name}</option>
                  ))}
                </select>
              </div>

              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Macmiilka (Tenant Name)</label>
                <input
                  type="text"
                  required
                  value={formData.tenantName}
                  onChange={(e) => setFormData({ ...formData, tenantName: e.target.value })}
                  className="w-full px-5 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl text-sm font-semibold focus:ring-2 focus:ring-teal-500 outline-none transition-all"
                  placeholder="Magaca macmiilka..."
                />
              </div>

              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Cillada Jirta (The Issue)</label>
                <textarea
                  required
                  rows={3}
                  value={formData.issue}
                  onChange={(e) => setFormData({ ...formData, issue: e.target.value })}
                  className="w-full px-5 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl text-sm font-semibold focus:ring-2 focus:ring-teal-500 outline-none transition-all resize-none"
                  placeholder="Maxaa u baahan dayactir?"
                />
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Ahmiyadda (Priority)</label>
                  <select
                    value={formData.priority}
