  const handleOpenModal = (sale?: Sale) => {
    if (sale) {
      setEditingSale(sale);
      setFormData(sale);
    } else {
      setEditingSale(null);
      setFormData({
        propertyId: properties[0]?.id || '',
        clientName: '',
        amount: 0,
        transactionType: 'Sale',
        date: new Date().toISOString().split('T')[0],
        status: 'Pending'
      });
