import { Property, Tenant, MaintenanceRequest, Sale, RentRecord, FinancialRecord } from './types';
import { properties as initialProperties, tenants as initialTenants, maintenanceRequests as initialMaintenance, sales as initialSales } from './mockData';

// Keys for localStorage
const DB_KEYS = {
  PROPERTIES: 'eliteestate_properties',
  TENANTS: 'eliteestate_tenants',
  MAINTENANCE: 'eliteestate_maintenance',
  SALES: 'eliteestate_sales',
  RENTS: 'eliteestate_rents',
  FINANCIALS: 'eliteestate_financials'
};

class ApiService {
  private get<T>(key: string, initialData: T[]): T[] {
    const data = localStorage.getItem(key);
    if (!data) {
      localStorage.setItem(key, JSON.stringify(initialData));
      return initialData;
    }
    return JSON.parse(data);
  }

  private set<T>(key: string, data: T[]): void {
    localStorage.setItem(key, JSON.stringify(data));
  }

  // Properties
  async getProperties(): Promise<Property[]> {
    return this.get(DB_KEYS.PROPERTIES, initialProperties);
  }

  async saveProperties(data: Property[]): Promise<void> {
    this.set(DB_KEYS.PROPERTIES, data);
  }

  // Tenants
  async getTenants(): Promise<Tenant[]> {
    return this.get(DB_KEYS.TENANTS, initialTenants);
  }

  async saveTenants(data: Tenant[]): Promise<void> {
    this.set(DB_KEYS.TENANTS, data);
  }

  // Maintenance
  async getMaintenance(): Promise<MaintenanceRequest[]> {
    return this.get(DB_KEYS.MAINTENANCE, initialMaintenance);
  }

  async saveMaintenance(data: MaintenanceRequest[]): Promise<void> {
    this.set(DB_KEYS.MAINTENANCE, data);
  }

  // Sales
  async getSales(): Promise<Sale[]> {
    return this.get(DB_KEYS.SALES, initialSales);
  }

  async saveSales(data: Sale[]): Promise<void> {
    this.set(DB_KEYS.SALES, data);
  }

  // Rents
  async getRents(): Promise<RentRecord[]> {
    return this.get(DB_KEYS.RENTS, [
      { id: 'r1', propertyId: '1', tenantName: 'Abdi Rahman', amount: 450, dueDate: '2024-06-01', status: 'Pending' },
      { id: 'r2', propertyId: '3', tenantName: 'Global Tech', amount: 3500, dueDate: '2024-06-01', status: 'Paid' }
    ]);
  }

  async saveRents(data: RentRecord[]): Promise<void> {
    this.set(DB_KEYS.RENTS, data);
  }

  // Financials
  async getFinancials(): Promise<FinancialRecord[]> {
    return this.get(DB_KEYS.FINANCIALS, [
      { id: 'f1', date: '2024-05-01', clientName: 'Ahmed Ali', description: 'Iibka Villa Hilaac', totalAmount: 150000, paidAmount: 150000, category: 'Income', status: 'Paid' }
    ]);
  }

  async saveFinancials(data: FinancialRecord[]): Promise<void> {
    this.set(DB_KEYS.FINANCIALS, data);
  }
}

export const api = new ApiService();

