    if (window.confirm('Ma hubtaa inaad tirtirto gurigan?')) {
      const newList = propertyList.filter(p => p.id !== id);
      setPropertyList(newList);
      await api.saveProperties(newList);
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setFormData({ ...formData, image: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    let newList: Property[];

    if (editingProperty) {
      newList = propertyList.map(p => p.id === editingProperty.id ? { ...p, ...formData } as Property : p);
    } else {
      const newProperty: Property = {
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
