                {editingProperty ? 'Keydi Isbadalka' : 'DHAMAYSTIR DHISMAHA'}
              </button>
            </form>
          </div>
        </div>
      )}

      {/* Insights Modal */}
      {isInsightsOpen && selectedProperty && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/80 backdrop-blur-md" onClick={handleCloseInsights}></div>
          <div className="bg-white rounded-[3rem] w-full max-w-4xl relative z-10 shadow-2xl animate-in slide-in-from-bottom duration-500 overflow-hidden border border-teal-500/30">
            {/* Modal Header */}
            <div className="p-8 bg-slate-900 text-white flex items-center justify-between">
              <div className="flex items-center gap-4">
                <div className="w-16 h-16 rounded-2xl overflow-hidden border-2 border-teal-500">
                   <img src={selectedProperty.image} className="w-full h-full object-cover" />
                </div>
                <div>
                   <h2 className="text-2xl font-black tracking-tight">{selectedProperty.name}</h2>
                   <div className="flex items-center gap-4 mt-1">
                      <p className="text-slate-400 text-xs font-bold uppercase tracking-widest">{selectedProperty.address}</p>
                      <div className="flex gap-3 text-teal-400 text-[10px] font-black uppercase">
                        <span><i className="fa-solid fa-bed mr-1"></i> {selectedProperty.rooms} Qol</span>
                        <span><i className="fa-solid fa-kitchen-set mr-1"></i> {selectedProperty.kitchens} Jiko</span>
                        <span><i className="fa-solid fa-sink mr-1"></i> {selectedProperty.bathrooms} Sooli</span>
                      </div>
                   </div>
                </div>
              </div>
              <button onClick={handleCloseInsights} className="w-12 h-12 rounded-full bg-white/10 hover:bg-rose-500 transition-colors flex items-center justify-center">
                <i className="fa-solid fa-xmark text-xl text-white"></i>
              </button>
            </div>

            {/* Modal Tabs */}
            <div className="flex p-4 bg-slate-50 border-b border-slate-100 overflow-x-auto gap-2">
              {[
                { id: 'Tenants', label: 'Macmiisha', icon: 'fa-users' },
                { id: 'Rents', label: 'Kirada', icon: 'fa-file-invoice-dollar' },
                { id: 'Sales', label: 'Iibka/Ganacsiga', icon: 'fa-handshake' }
              ].map(tab => (
                <button
                  key={tab.id}
                  onClick={() => setActiveInsightTab(tab.id as any)}
                  className={`flex items-center gap-2 px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest whitespace-nowrap transition-all ${
                    activeInsightTab === tab.id ? 'bg-teal-600 text-white shadow-lg' : 'bg-white text-slate-500 border border-slate-200'
                  }`}
                >
                  <i className={`fa-solid ${tab.icon}`}></i>
                  {tab.label}
                </button>
              ))}
            </div>

            {/* Modal Content */}
            <div className="p-8 max-h-[60vh] overflow-y-auto">
              {activeInsightTab === 'Tenants' && (
                <div className="space-y-4">
                   {tenants.filter(t => t.propertyId === selectedProperty.id).length > 0 ? (
                     tenants.filter(t => t.propertyId === selectedProperty.id).map(t => (
                        <div key={t.id} className="flex items-center justify-between p-5 bg-slate-50 rounded-[2rem] border border-slate-100">
                          <div className="flex items-center gap-4">
                             <div className="w-12 h-12 rounded-2xl bg-teal-100 text-teal-600 flex items-center justify-center font-black">{t.name.charAt(0)}</div>
                             <div>
                                <p className="font-black text-slate-900">{t.name}</p>
                                <p className="text-[10px] font-bold text-slate-400 uppercase">Unit: {t.unit} • {t.email}</p>
                             </div>
                          </div>
                          <span className="px-3 py-1 bg-teal-50 text-teal-600 text-[10px] font-black rounded-lg uppercase">{t.status}</span>
                        </div>
                     ))
                   ) : (
                     <div className="py-20 text-center opacity-30">
                        <i className="fa-solid fa-users-slash text-5xl mb-4"></i>
                        <p className="font-black uppercase tracking-widest">Ma jiraan macmiil degan</p>
                     </div>
                   )}
                </div>
              )}

              {activeInsightTab === 'Rents' && (
                <div className="space-y-4">
                  {rents.filter(r => r.propertyId === selectedProperty.id).length > 0 ? (
                     rents.filter(r => r.propertyId === selectedProperty.id).map(r => (
                        <div key={r.id} className="flex items-center justify-between p-5 bg-slate-50 rounded-[2rem] border border-slate-100">
                           <div className="flex items-center gap-4">
                              <div className="w-12 h-12 rounded-2xl bg-teal-600 text-white flex items-center justify-center"><i className="fa-solid fa-money-bill-1"></i></div>
                              <div>
                                 <p className="font-black text-slate-900">{r.tenantName}</p>
                                 <p className="text-[10px] font-bold text-slate-400 uppercase">Bixinta: {r.dueDate}</p>
                              </div>
                           </div>
                           <div className="text-right">
                              <p className="text-lg font-black text-teal-600">${r.amount}</p>
                              <span className={`text-[9px] font-black uppercase px-2 py-0.5 rounded ${r.status === 'Paid' ? 'bg-emerald-500 text-white' : 'bg-rose-500 text-white'}`}>{r.status}</span>
                           </div>
                        </div>
                     ))
                  ) : (
                    <div className="py-20 text-center opacity-30">
                       <i className="fa-solid fa-file-circle-xmark text-5xl mb-4"></i>
                       <p className="font-black uppercase tracking-widest">Ma jiro diiwaan kiro ah</p>
                    </div>
                  )}
                </div>
              )}

              {activeInsightTab === 'Sales' && (
                <div className="space-y-4">
                  {sales.filter(s => s.propertyId === selectedProperty.id).length > 0 ? (
                     sales.filter(s => s.propertyId === selectedProperty.id).map(s => (
                        <div key={s.id} className="flex items-center justify-between p-5 bg-slate-50 rounded-[2rem] border border-slate-100">
                           <div className="flex items-center gap-4">
                              <div className="w-12 h-12 rounded-2xl bg-amber-500 text-white flex items-center justify-center"><i className="fa-solid fa-handshake"></i></div>
                              <div>
                                 <p className="font-black text-slate-900">{s.clientName}</p>
                                 <p className="text-[10px] font-bold text-slate-400 uppercase">Heshiis: {s.transactionType} • {s.date}</p>
                              </div>
                           </div>
                           <div className="text-right">
                              <p className="text-lg font-black text-slate-900">${s.amount.toLocaleString()}</p>
                              <span className="text-[9px] font-black uppercase bg-teal-600 text-white px-2 py-0.5 rounded">{s.status}</span>
                           </div>
                        </div>
                     ))
                  ) : (
                    <div className="py-20 text-center opacity-30">
                       <i className="fa-solid fa-handshake-slash text-5xl mb-4"></i>
                       <p className="font-black uppercase tracking-widest">Ma jiro heshiis iib/kireyn ah</p>
                    </div>
                  )}
                </div>
              )}
            </div>

            {/* Modal Footer Summary */}
            <div className="p-8 bg-slate-50 border-t border-slate-100 flex items-center justify-between">
               <div className="flex gap-8">
                  <div>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Xaaladda Hadda</p>
                    <p className="text-sm font-black text-slate-900">{selectedProperty.status}</p>
                  </div>
                  <div>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Dhismaha Ka Kooban</p>
                    <p className="text-sm font-black text-slate-900">{selectedProperty.rooms} Qol, {selectedProperty.kitchens} Jiko, {selectedProperty.bathrooms} Sooli</p>
                  </div>
               </div>
               <div className="text-right">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Qiimaha Bishii</p>
                  <p className="text-2xl font-black text-teal-600">${selectedProperty.price}</p>
               </div>
            </div>
          </div>
        </div>
      )}

      {!loading && filteredProperties.length === 0 && (
        <div className="flex flex-col items-center justify-center py-24 bg-white rounded-[3rem] border-2 border-dashed border-slate-200">
          <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mb-6">
            <i className="fa-solid fa-magnifying-glass text-slate-300 text-3xl"></i>
          </div>
          <h3 className="text-xl font-black text-slate-900">Waxba Lama Helin</h3>
          <p className="text-slate-500 font-medium">Isku day inaad badasho shaandheynta (filters).</p>
        </div>
      )}
    </div>
  );
};

export default Properties;

import React, { useState, useEffect, useRef } from 'react';
import { api } from '../apiService';
import { Property, Tenant, RentRecord, Sale } from '../types';

const Properties: React.FC = () => {
  const [propertyList, setPropertyList] = useState<Property[]>([]);
  const [tenants, setTenants] = useState<Tenant[]>([]);
  const [rents, setRents] = useState<RentRecord[]>([]);
  const [sales, setSales] = useState<Sale[]>([]);

  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('All');
  const [typeFilter, setTypeFilter] = useState('All');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Modal states
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isInsightsOpen, setIsInsightsOpen] = useState(false);
  const [editingProperty, setEditingProperty] = useState<Property | null>(null);
  const [selectedProperty, setSelectedProperty] = useState<Property | null>(null);
  const [activeInsightTab, setActiveInsightTab] = useState<'Tenants' | 'Rents' | 'Sales'>('Tenants');

  // Form states
  const [formData, setFormData] = useState<Partial<Property>>({
    name: '',
    address: '',
    type: 'Apartment',
    status: 'Vacant',
    price: 0,
    rooms: 1,
    kitchens: 1,
    bathrooms: 1,
    image: 'https://images.unsplash.com/photo-1560518883-ce09059eeffa?auto=format&fit=crop&w=800&q=80'
  });

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    try {
      const [pData, tData, rData, sData] = await Promise.all([
        api.getProperties(),
        api.getTenants(),
        api.getRents(),
        api.getSales()
      ]);
      setPropertyList(pData);
      setTenants(tData);
      setRents(rData);
      setSales(sData);
    } catch (error) {
      console.error("Failed to load data", error);
    }
    setLoading(false);
  };

  const filteredProperties = propertyList.filter(p => {
    const statusMatch = filter === 'All' || p.status === filter;
    const typeMatch = typeFilter === 'All' || p.type === typeFilter;
    return statusMatch && typeMatch;
  });

  const handleOpenModal = (property?: Property) => {
    if (property) {
      setEditingProperty(property);
      setFormData(property);
    } else {
      setEditingProperty(null);
      setFormData({
        name: '',
        address: '',
        type: 'Apartment',
        status: 'Vacant',
        price: 0,
        rooms: 1,
        kitchens: 1,
        bathrooms: 1,
        image: 'https://images.unsplash.com/photo-1560518883-ce09059eeffa?auto=format&fit=crop&w=800&q=80'
      });
    }
    setIsModalOpen(true);
  };

  const handleOpenInsights = (property: Property) => {
    setSelectedProperty(property);
    setIsInsightsOpen(true);
    setActiveInsightTab('Tenants');
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setEditingProperty(null);
  };

  const handleCloseInsights = () => {
    setIsInsightsOpen(false);
    setSelectedProperty(null);
  };

  const handleDelete = async (id: string) => {
    if (window.confirm('Ma hubtaa inaad tirtirto gurigan?')) {
      const newList = propertyList.filter(p => p.id !== id);
      setPropertyList(newList);
      await api.saveProperties(newList);
    }
  };

  // Improved Image Compression Logic
  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const img = new Image();
        img.onload = () => {
          const canvas = document.createElement('canvas');
          const MAX_WIDTH = 800; // Resize to max 800px width
          const scaleSize = MAX_WIDTH / img.width;

          canvas.width = MAX_WIDTH;
          canvas.height = img.height * scaleSize;

          const ctx = canvas.getContext('2d');
          if (ctx) {
            ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
            // Compress image to JPEG with 0.7 quality to save space
            const compressedBase64 = canvas.toDataURL('image/jpeg', 0.7);
            setFormData({ ...formData, image: compressedBase64 });
          }
        };
        img.src = event.target?.result as string;
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    let newList: Property[];

    if (editingProperty) {
      newList = propertyList.map(p => p.id === editingProperty.id ? { ...p, ...formData } as Property : p);
    } else {
      const newProperty: Property = {
        ...formData,
        id: Math.random().toString(36).substr(2, 9),
      } as Property;
      newList = [newProperty, ...propertyList];
    }

    setPropertyList(newList);
    await api.saveProperties(newList);
    handleCloseModal();
  };

  const getStatusBadge = (status: string) => {
    switch (status) {
      case 'Occupied':
        return <span className="px-3 py-1 bg-rose-500 text-white text-[10px] font-black uppercase tracking-widest rounded-full shadow-lg">La Deggan Yahay</span>;
      case 'Vacant':
        return <span className="px-3 py-1 bg-emerald-500 text-white text-[10px] font-black uppercase tracking-widest rounded-full shadow-lg">Waa Bannaan Yahay</span>;
      default:
        return <span className="px-3 py-1 bg-amber-500 text-white text-[10px] font-black uppercase tracking-widest rounded-full shadow-lg">Dayactir</span>;
    }
  };

  const getTypeIcon = (type: string) => {
    switch (type) {
      case 'Apartment': return 'fa-building-user';
      case 'House': return 'fa-house-chimney';
      case 'Hotel': return 'fa-hotel';
      case 'Commercial': return 'fa-shop';
      default: return 'fa-building';
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-full">
        <div className="flex flex-col items-center gap-4">
          <i className="fa-solid fa-circle-notch fa-spin text-4xl text-teal-600"></i>
          <p className="text-xs font-black text-slate-400 uppercase tracking-widest">Loading Database...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="p-8 space-y-8 animate-in fade-in duration-700 relative text-slate-900">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">Guryaha & Ganacsiga</h1>
          <p className="text-slate-500 font-medium mt-1">Maamul dhammaan macluumaadka guryahaaga.</p>
        </div>

        <div className="flex flex-wrap gap-3">
          <div className="flex bg-white p-1 rounded-2xl border border-slate-200 shadow-sm">
            {['All', 'Occupied', 'Vacant'].map(tab => (
              <button
                key={tab}
                onClick={() => setFilter(tab)}
                className={`px-4 py-2 rounded-xl text-xs font-bold transition-all ${
                  filter === tab ? 'bg-teal-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-800'
                }`}
              >
                {tab === 'All' ? 'Dhammaan' : tab === 'Occupied' ? 'Lagu Jiro' : 'Bannaan'}
              </button>
            ))}
          </div>

          <select 
            value={typeFilter}
            onChange={(e) => setTypeFilter(e.target.value)}
