// Halkan dhig URL-ka backend-kaaga marka uu shaqaynayo
const BASE_URL = 'http://localhost:5000/api';

class ApiService {
  private async request<T>(endpoint: string, options?: RequestInit): Promise<T> {
    try {
      const response = await fetch(`${BASE_URL}${endpoint}`, {
        ...options,
        headers: {
          'Content-Type': 'application/json',
          ...options?.headers,
        },
      });

      if (!response.ok) {
        const errorData = await response.json().catch(() => ({}));
        throw new Error(errorData.message || `API Error: ${response.status}`);
      }

      return await response.json();
    } catch (error) {
      console.error(`Error requesting ${endpoint}:`, error);
      // Haddii backend-ku uusan shaqaynayn, waxaan dib ugu laabanaynaa localStorage si uusan app-ku u istaagin (Fallback)
      console.warn("Backend ma shaqaynayo, hubi 'server.js'");
      throw error;
    }
  }

  // Properties
  async getProperties(): Promise<Property[]> {
    return this.request<Property[]>('/properties').catch(() => {
      const data = localStorage.getItem('eliteestate_properties');
      return data ? JSON.parse(data) : [];
    });
  }

  async saveProperties(data: Property[]): Promise<void> {
    // Waxaan u diraynaa backend-ka mid mid ama dhamaan (Halkan waxaan u tusaaleynaynaa keydinta localStorage sidoo kale)
    localStorage.setItem('eliteestate_properties', JSON.stringify(data));

    // Tusaale: Haddii aad hal mid dirayso (Last added)
    if (data.length > 0) {
      const lastProperty = data[0];
      await this.request('/properties', {
        method: 'POST',
        body: JSON.stringify(lastProperty),
      }).catch(err => console.error("Backend save failed:", err));
    }
  }

  // Tenants
  async getTenants(): Promise<Tenant[]> {
    return this.request<Tenant[]>('/tenants').catch(() => []);
  }

  async saveTenants(data: Tenant[]): Promise<void> {
    localStorage.setItem('eliteestate_tenants', JSON.stringify(data));
  }

  // Maintenance
  async getMaintenance(): Promise<MaintenanceRequest[]> {
    return this.request<MaintenanceRequest[]>('/maintenance').catch(() => []);
  }

  // Sales
  async getSales(): Promise<Sale[]> {
    return this.request<Sale[]>('/sales').catch(() => []);
  }

  // Rents
  async getRents(): Promise<RentRecord[]> {
    return this.request<RentRecord[]>('/rents').catch(() => []);
  }

  // Financials
  async getFinancials(): Promise<FinancialRecord[]> {
    return this.request<FinancialRecord[]>('/financials').catch(() => []);
  }
}

export const api = new ApiService();

/**
 * BACKEND SERVER (Node.js + Express + MongoDB)
 * 
 * Si aad u isticmaasho:
 * 1. npm install express mongoose cors dotenv
 * 2. node server.js
 */

const express = require('express');
const mongoose = require('mongoose');
const cors = require('cors');
require('dotenv').config();

const app = express();
const PORT = process.env.PORT || 5000;

// Middleware
app.use(cors());
app.use(express.json({ limit: '10mb' })); // Si sawirada loogu gudbin karo

// MongoDB Connection
// FIIRO GAAR AH: Halkan dhig URL-kaaga MongoDB Atlas (ka soo qaado account-kaaga)
const MONGODB_URI = process.env.MONGODB_URI || 'mongodb://localhost:27017/eliteestate';

mongoose.connect(MONGODB_URI)
  .then(() => console.log('✅ MongoDB Connected!'))
  .catch(err => console.error('❌ MongoDB Connection Error:', err));

// Property Schema
const propertySchema = new mongoose.Schema({
  id: String,
  name: String,
  address: String,
  type: String,
  status: String,
  price: Number,
  rooms: Number,
  kitchens: Number,
  bathrooms: Number,
  image: String
});

const Property = mongoose.model('Property', propertySchema);

// API Routes
app.get('/api/properties', async (req, res) => {
  try {
    const properties = await Property.find().sort({ _id: -1 });
    res.json(properties);
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
});

app.post('/api/properties', async (req, res) => {
  try {
    // Hubi haddii uu jiro (Update) ama mid cusub (Create)
    const existing = await Property.findOne({ id: req.body.id });
    if (existing) {
      Object.assign(existing, req.body);
      await existing.save();
      return res.json(existing);
    }

    const newProperty = new Property(req.body);
    const saved = await newProperty.save();
    res.status(201).json(saved);
  } catch (err) {
    res.status(400).json({ message: err.message });
  }
});

app.delete('/api/properties/:id', async (req, res) => {
  try {
    await Property.findOneAndDelete({ id: req.params.id });
    res.json({ message: 'Property deleted successfully' });
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
});

// Health Check
app.get('/', (req, res) => {
  res.send('EliteEstate API is running...');
});

app.listen(PORT, () => {
  console.log(`🚀 Server is running on http://localhost:${PORT}`);
});

