      setEditingProperty(null);
      setFormData({
        name: '', address: '', type: 'Apartment', status: 'Vacant', price: 0, rooms: 1, kitchens: 1, bathrooms: 1, image: 'https://images.unsplash.com/photo-1560518883-ce09059eeffa?auto=format&fit=crop&w=800&q=80'
      });
    }
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setEditingProperty(null);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    let newList: Property[];
    if (editingProperty) {
      newList = propertyList.map(p => p.id === editingProperty.id ? { ...p, ...formData } as Property : p);
    } else {
      const newProperty: Property = { ...formData, id: Math.random().toString(36).substr(2, 9) } as Property;
      newList = [newProperty, ...propertyList];
