import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from '@google/genai';
import { properties, tenants, maintenanceRequests } from '../mockData';

interface Message {
  role: 'user' | 'bot';
  text: string;
  timestamp: string;
}

const Communications: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    {
      role: 'bot',
      text: "Ku soo dhawaaw EliteEstate AI! Waxaan ahay caawiyahaaga dhijitaalka ah. Maxaan kuu qabtaa maanta?",
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, isTyping]);

  const handleSend = async (customText?: string) => {
    const textToSend = customText || input;
    if (!textToSend.trim()) return;

    setMessages(prev => [...prev, {
      role: 'user',
      text: textToSend,
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    }]);
    setInput('');
    setIsTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const context = `System State: ${properties.length} props, ${tenants.length} tenants.`;
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: textToSend,
        config: {
          systemInstruction: `Respond as EliteEstate AI assistant in Somalia. Use Somali language. Context: ${context}`,
        },
      });

      setMessages(prev => [...prev, {
        role: 'bot',
        text: response.text || "Raalli ahow, hadda ma shaqeyn karo.",
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
      }]);
    } catch (error) {
      console.error("AI Chat Error:", error);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="h-[calc(100vh-64px)] flex flex-col bg-slate-50">
      <div className="bg-white border-b border-slate-200 px-8 py-4 flex items-center gap-4">
        <div className="w-12 h-12 bg-teal-600 rounded-2xl flex items-center justify-center shadow-lg"><i className="fa-solid fa-robot text-white"></i></div>
        <div>
           <h2 className="text-lg font-black text-slate-900">EliteEstate AI</h2>
           <p className="text-[10px] font-black text-emerald-500 uppercase">Online & Ready</p>
        </div>
      </div>
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-8 space-y-6">
        {messages.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[80%] p-5 rounded-[2rem] text-sm font-medium ${msg.role === 'user' ? 'bg-teal-600 text-white rounded-tr-none' : 'bg-white text-slate-800 border border-slate-100 rounded-tl-none shadow-sm'}`}>
              {msg.text}
              <p className={`text-[8px] font-black uppercase mt-2 ${msg.role === 'user' ? 'text-teal-200' : 'text-slate-300'}`}>{msg.timestamp}</p>
            </div>
          </div>
        ))}
        {isTyping && <div className="text-[10px] font-black text-slate-400 uppercase animate-pulse">AI is thinking...</div>}
      </div>
      <div className="p-8 bg-white border-t border-slate-200">
        <form onSubmit={(e) => { e.preventDefault(); handleSend(); }} className="flex gap-4">
          <input value={input} onChange={(e) => setInput(e.target.value)} className="flex-1 bg-slate-50 border-none rounded-[2rem] px-6 py-4 text-sm font-semibold focus:ring-2 focus:ring-teal-500 transition-all outline-none" placeholder="Wax i weydii..." />
          <button type="submit" className="w-14 h-14 bg-teal-600 text-white rounded-2xl shadow-xl shadow-teal-600/20 active:scale-95 transition-all flex items-center justify-center"><i className="fa-solid fa-paper-plane"></i></button>
        </form>
      </div>
    </div>
  );
};

