import React, { useState } from 'react';
import { tenants as initialTenants, properties } from '../mockData';
import { Tenant } from '../types';

const Tenants: React.FC = () => {
  const [tenantList, setTenantList] = useState<Tenant[]>(initialTenants);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingTenant, setEditingTenant] = useState<Tenant | null>(null);

  const [formData, setFormData] = useState<Partial<Tenant>>({
    name: '', email: '', phone: '', propertyId: properties[0]?.id || '', unit: '',
    leaseStart: new Date().toISOString().split('T')[0],
    leaseEnd: new Date(new Date().setFullYear(new Date().getFullYear() + 1)).toISOString().split('T')[0],
    status: 'Active'
  });

  const getPropertyName = (id: string) => properties.find(p => p.id === id)?.name || 'Dhismaha lama helin';

  const handleOpenModal = (tenant?: Tenant) => {
    if (tenant) {
      setEditingTenant(tenant);
      setFormData(tenant);
    } else {
      setEditingTenant(null);
      setFormData({
        name: '', email: '', phone: '', propertyId: properties[0]?.id || '', unit: '',
        leaseStart: new Date().toISOString().split('T')[0],
        leaseEnd: new Date(new Date().setFullYear(new Date().getFullYear() + 1)).toISOString().split('T')[0],
        status: 'Active'
      });
    }
    setIsModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingTenant) {
      setTenantList(prev => prev.map(t => t.id === editingTenant.id ? { ...t, ...formData } as Tenant : t));
    } else {
      const newTenant: Tenant = { ...formData, id: Math.random().toString(36).substr(2, 9) } as Tenant;
      setTenantList(prev => [newTenant, ...prev]);
    }
    setIsModalOpen(false);
  };

  return (
    <div className="p-8 space-y-8 animate-in fade-in duration-500">
      <div className="flex justify-between items-center">
        <h1 className="text-2xl font-black text-slate-900 tracking-tight">Maamulka Macmiisha</h1>
        <button onClick={() => handleOpenModal()} className="px-6 py-3 bg-teal-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-teal-600/20 active:scale-95">
          <i className="fa-solid fa-user-plus mr-2"></i> Kudar Macmiil
        </button>
      </div>

      <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50 border-b border-slate-100">
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Macmiilka</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Dhismaha</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Status</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {tenantList.map(tenant => (
              <tr key={tenant.id} className="hover:bg-slate-50/50">
                <td className="px-8 py-5 font-bold text-slate-900">{tenant.name}</td>
                <td className="px-8 py-5 text-sm text-slate-500">{getPropertyName(tenant.propertyId)} (Unit: {tenant.unit})</td>
                <td className="px-8 py-5">
                  <span className={`px-3 py-1 rounded-lg text-[9px] font-black uppercase ${tenant.status === 'Active' ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>
                    {tenant.status}
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

