import { Property, Tenant, MaintenanceRequest, Sale, RentRecord, FinancialRecord } from './types';

const BASE_URL = 'http://localhost:5000/api';

class ApiService {
  private async request<T>(endpoint: string, options?: RequestInit): Promise<T> {
    try {
      const response = await fetch(`${BASE_URL}${endpoint}`, {
        ...options,
        headers: {
          'Content-Type': 'application/json',
          ...options?.headers,
        },
      });

      if (!response.ok) {
        const errorData = await response.json().catch(() => ({}));
        throw new Error(errorData.message || `API Error: ${response.status}`);
      }

      return await response.json();
    } catch (error) {
      console.error(`Error requesting ${endpoint}:`, error);
      // Fallback to localStorage if server is down
      const storageKey = `eliteestate_${endpoint.replace('/api/', '')}`;
      const localData = localStorage.getItem(storageKey);
      if (localData) return JSON.parse(localData);
      return [] as any;
    }
  }

  async getProperties(): Promise<Property[]> {
    return this.request<Property[]>('/properties');
  }

  async saveProperties(data: Property[]): Promise<void> {
    localStorage.setItem('eliteestate_properties', JSON.stringify(data));
    const lastItem = data[0];
    if (lastItem) {
      await this.request('/properties', {
        method: 'POST',
        body: JSON.stringify(lastItem),
      });
    }
  }

  async getTenants(): Promise<Tenant[]> {
    return this.request<Tenant[]>('/tenants');
  }

  async getSales(): Promise<Sale[]> {
    return this.request<Sale[]>('/sales');
  }

  async getRents(): Promise<RentRecord[]> {
    return this.request<RentRecord[]>('/rents');
  }
}

export const api = new ApiService();

