      return await response.json();
    } catch (error) {
      console.error(error);
      const storageKey = `eliteestate_${endpoint.replace('/', '')}`;
      return JSON.parse(localStorage.getItem(storageKey) || '[]');
    }
  }

  async getProperties(): Promise<Property[]> {
    return this.request<Property[]>('/properties');
  }

