import { Property, Tenant, Sale, RentRecord, MaintenanceRequest, FinancialRecord } from './types';
import * as mock from './mockData';

const BASE_URL = 'http://localhost:5000/api';

class ApiService {
  private async request<T>(endpoint: string, options?: RequestInit): Promise<T> {
    try {
      const response = await fetch(`${BASE_URL}${endpoint}`, {
        ...options,
        headers: {
          'Content-Type': 'application/json',
          ...options?.headers,
        },
      });

      if (!response.ok) throw new Error(`API Error: ${response.status}`);
      return await response.json();
    } catch (error) {
      console.warn(`Server unstable for ${endpoint}, using local storage/mock data.`);
      const storageKey = `eliteestate_${endpoint.replace('/', '')}`;
      const local = localStorage.getItem(storageKey);
      if (local) return JSON.parse(local);

      // Fallback to mock data if nothing in localStorage
      if (endpoint === '/properties') return mock.properties as any;
      if (endpoint === '/tenants') return mock.tenants as any;
      if (endpoint === '/sales') return mock.sales as any;
      if (endpoint === '/maintenance') return mock.maintenanceRequests as any;

      return [] as any;
    }
  }

  async getProperties(): Promise<Property[]> {
    return this.request<Property[]>('/properties');
  }

  async saveProperties(data: Property[]): Promise<void> {
    localStorage.setItem('eliteestate_properties', JSON.stringify(data));
    if (data.length > 0) {
      await this.request('/properties', {
        method: 'POST',
        body: JSON.stringify(data[0]),
      });
    }
  }

  async getTenants(): Promise<Tenant[]> { return this.request<Tenant[]>('/tenants'); }
  async getSales(): Promise<Sale[]> { return this.request<Sale[]>('/sales'); }
  async getRents(): Promise<RentRecord[]> { return this.request<RentRecord[]>('/rents'); }
  async getMaintenance(): Promise<MaintenanceRequest[]> { return this.request<MaintenanceRequest[]>('/maintenance'); }
}

export const api = new ApiService();

