  .then(() => console.log('✅ MongoDB Connected!'))
  .catch(err => console.error('❌ MongoDB Connection Error:', err));

// Schemas
const propertySchema = new mongoose.Schema({
  id: String, name: String, address: String, type: String, status: String,
  price: Number, rooms: Number, kitchens: Number, bathrooms: Number, image: String
});

const tenantSchema = new mongoose.Schema({
  id: String, name: String, propertyId: String, unit: String, email: String,
  phone: String, leaseStart: String, leaseEnd: String, status: String
});

const saleSchema = new mongoose.Schema({
  id: String, propertyId: String, clientName: String, amount: Number,
  date: String, transactionType: String, status: String
});

const Property = mongoose.model('Property', propertySchema);
