import { Property, Tenant, Sale, RentRecord, MaintenanceRequest, FinancialRecord } from './types';
import * as mock from './mockData';

const BASE_URL = 'http://localhost:5000/api';

class ApiService {
  private async request<T>(endpoint: string, options?: RequestInit): Promise<T> {
    try {
      const response = await fetch(`${BASE_URL}${endpoint}`, {
        ...options,
        headers: {
          'Content-Type': 'application/json',
          ...options?.headers,
        },
      });

      if (!response.ok) {
        const errorBody = await response.json().catch(() => ({}));
        throw new Error(errorBody.message || `API Error: ${response.status}`);
      }
      return await response.json();
    } catch (error) {
      console.warn(`Server interaction failed for ${endpoint}, using local fallback.`);

      // Local fallback logic for demo purposes if server is down
      if (endpoint === '/properties' && (!options || options.method === 'GET')) {
        const local = localStorage.getItem('eliteestate_properties');
        return local ? JSON.parse(local) : mock.properties as any;
      }

      throw error;
    }
  }

  async getProperties(): Promise<Property[]> {
    return this.request<Property[]>('/properties');
  }

  async createProperty(property: Property): Promise<Property> {
    return this.request<Property>('/properties', {
      method: 'POST',
      body: JSON.stringify(property),
    });
  }

  async updateProperty(id: string, property: Property): Promise<Property> {
    return this.request<Property>(`/properties/${id}`, {
      method: 'PUT',
      body: JSON.stringify(property),
    });
  }

  async deleteProperty(id: string): Promise<void> {
    return this.request<void>(`/properties/${id}`, {
      method: 'DELETE',
    });
  }

  async getTenants(): Promise<Tenant[]> { return this.request<Tenant[]>('/tenants'); }
  async getSales(): Promise<Sale[]> { return this.request<Sale[]>('/sales'); }
  async getRents(): Promise<RentRecord[]> { return this.request<RentRecord[]>('/rents'); }
  async getMaintenance(): Promise<MaintenanceRequest[]> { return this.request<MaintenanceRequest[]>('/maintenance'); }
}

export const api = new ApiService();

const express = require('express');
const mongoose = require('mongoose');
const cors = require('cors');
require('dotenv').config();

const app = express();
const PORT = process.env.PORT || 5000;

app.use(cors());
app.use(express.json({ limit: '10mb' }));

const MONGODB_URI = process.env.MONGODB_URI || 'mongodb://localhost:27017/eliteestate';

mongoose.connect(MONGODB_URI)
  .then(() => console.log('✅ MongoDB Connected!'))
  .catch(err => console.error('❌ MongoDB Connection Error:', err));

// Schemas
const propertySchema = new mongoose.Schema({
  id: { type: String, required: true, unique: true },
  name: String,
  address: String,
  type: String,
  status: String,
  price: Number,
  rooms: Number,
  kitchens: Number,
  bathrooms: Number,
  image: String
});

const Property = mongoose.model('Property', propertySchema);

// API Routes
app.get('/api/properties', async (req, res) => {
  try {
    const properties = await Property.find().sort({ _id: -1 });
    res.json(properties);
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
});

app.post('/api/properties', async (req, res) => {
  try {
    const newProperty = new Property(req.body);
    await newProperty.save();
    res.status(201).json(newProperty);
  } catch (err) {
    res.status(400).json({ message: err.message });
  }
});

app.put('/api/properties/:id', async (req, res) => {
  try {
    const updated = await Property.findOneAndUpdate({ id: req.params.id }, req.body, { new: true });
    if (!updated) return res.status(404).json({ message: 'Property not found' });
    res.json(updated);
  } catch (err) {
    res.status(400).json({ message: err.message });
  }
});

app.delete('/api/properties/:id', async (req, res) => {
  try {
    const deleted = await Property.findOneAndDelete({ id: req.params.id });
    if (!deleted) return res.status(404).json({ message: 'Property not found' });
    res.json({ message: 'Property deleted' });
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
});

app.listen(PORT, () => console.log(`🚀 Server on http://localhost:${PORT}`));

