const express = require('express');
const mongoose = require('mongoose');
const cors = require('cors');
require('dotenv').config();

const app = express();
const PORT = process.env.PORT || 5000;

app.use(cors());
app.use(express.json({ limit: '10mb' }));

const MONGODB_URI = process.env.MONGODB_URI || 'mongodb://localhost:27017/eliteestate';

mongoose.connect(MONGODB_URI)
  .then(() => console.log('✅ MongoDB Connected!'))
  .catch(err => console.error('❌ MongoDB Connection Error:', err));

// Properties Schema
const propertySchema = new mongoose.Schema({
  id: { type: String, required: true, unique: true },
  name: String,
  address: String,
  type: String,
  status: String,
  price: Number,
  rooms: Number,
  kitchens: Number,
  bathrooms: Number,
  image: String
});

const Property = mongoose.model('Property', propertySchema);

// Sales Schema
const saleSchema = new mongoose.Schema({
  id: { type: String, required: true, unique: true },
  propertyId: String,
  clientName: String,
  amount: Number,
  date: String,
  transactionType: String,
  status: String
});
const Sale = mongoose.model('Sale', saleSchema);

// Financial Records Schema
const financialSchema = new mongoose.Schema({
  id: { type: String, required: true, unique: true },
  date: String,
  clientName: String,
  description: String,
  totalAmount: Number,
  paidAmount: Number,
  category: String,
  status: String
});
const FinancialRecord = mongoose.model('FinancialRecord', financialSchema);

// --- PROPERTY ROUTES ---
app.get('/api/properties', async (req, res) => {
  try {
    const properties = await Property.find().sort({ _id: -1 });
    res.json(properties);
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
});

app.post('/api/properties', async (req, res) => {
  try {
    const newProperty = new Property(req.body);
    await newProperty.save();
    res.status(201).json(newProperty);
  } catch (err) {
    res.status(400).json({ message: err.message });
  }
});

app.put('/api/properties/:id', async (req, res) => {
  try {
    const updated = await Property.findOneAndUpdate({ id: req.params.id }, req.body, { new: true });
    if (!updated) return res.status(404).json({ message: 'Property not found' });
    res.json(updated);
  } catch (err) {
    res.status(400).json({ message: err.message });
  }
});

app.delete('/api/properties/:id', async (req, res) => {
  try {
    const deleted = await Property.findOneAndDelete({ id: req.params.id });
    if (!deleted) return res.status(404).json({ message: 'Property not found' });
    res.json({ message: 'Property deleted' });
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
});

// --- SALES ROUTES ---
app.get('/api/sales', async (req, res) => {
  try {
    const sales = await Sale.find().sort({ date: -1 });
    res.json(sales);
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
});

app.post('/api/sales', async (req, res) => {
  try {
    const newSale = new Sale(req.body);
    await newSale.save();
    res.status(201).json(newSale);
  } catch (err) {
    res.status(400).json({ message: err.message });
  }
});

app.delete('/api/sales/:id', async (req, res) => {
  try {
    const deleted = await Sale.findOneAndDelete({ id: req.params.id });
    res.json({ message: 'Sale deleted' });
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
});

// --- FINANCIAL ROUTES ---
