import { Property, Tenant, Sale, RentRecord, MaintenanceRequest, FinancialRecord } from './types';
import * as mock from './mockData';

const BASE_URL = 'http://localhost:5000/api';

class ApiService {
  private async request<T>(endpoint: string, options?: RequestInit): Promise<T> {
    try {
      const response = await fetch(`${BASE_URL}${endpoint}`, {
        ...options,
        headers: {
          'Content-Type': 'application/json',
          ...options?.headers,
        },
      });

      if (!response.ok) {
        const errorBody = await response.json().catch(() => ({}));
        throw new Error(errorBody.message || `API Error: ${response.status}`);
      }
      return await response.json();
    } catch (error) {
      console.warn(`Server interaction failed for ${endpoint}, using local fallback.`);

      // Local fallback for properties
      if (endpoint === '/properties' && (!options || options.method === 'GET')) {
        const local = localStorage.getItem('eliteestate_properties');
        return local ? JSON.parse(local) : mock.properties as any;
      }

      // Local fallback for sales
      if (endpoint === '/sales' && (!options || options.method === 'GET')) {
        const local = localStorage.getItem('eliteestate_sales');
        return local ? JSON.parse(local) : mock.sales as any;
      }

      throw error;
    }
  }

  // Properties
  async getProperties(): Promise<Property[]> {
    return this.request<Property[]>('/properties');
  }
  async createProperty(property: Property): Promise<Property> {
    return this.request<Property>('/properties', { method: 'POST', body: JSON.stringify(property) });
  }
  async updateProperty(id: string, property: Property): Promise<Property> {
    return this.request<Property>(`/properties/${id}`, { method: 'PUT', body: JSON.stringify(property) });
  }
  async deleteProperty(id: string): Promise<void> {
    return this.request<void>(`/properties/${id}`, { method: 'DELETE' });
  }

  // Sales
  async getSales(): Promise<Sale[]> {
    return this.request<Sale[]>('/sales');
  }
  async createSale(sale: Sale): Promise<Sale> {
    return this.request<Sale>('/sales', { method: 'POST', body: JSON.stringify(sale) });
  }
  async deleteSale(id: string): Promise<void> {
    return this.request<void>(`/sales/${id}`, { method: 'DELETE' });
  }

  // Financials
  async getFinancials(): Promise<FinancialRecord[]> {
    return this.request<FinancialRecord[]>('/financials');
  }
  async createFinancial(record: FinancialRecord): Promise<FinancialRecord> {
    return this.request<FinancialRecord>('/financials', { method: 'POST', body: JSON.stringify(record) });
  }
  async deleteFinancial(id: string): Promise<void> {
    return this.request<void>(`/financials/${id}`, { method: 'DELETE' });
  }

  // Others (Mock Fallback)
  async getTenants(): Promise<Tenant[]> { return this.request<Tenant[]>('/tenants').catch(() => mock.tenants as any); }
  async getMaintenance(): Promise<MaintenanceRequest[]> { return this.request<MaintenanceRequest[]>('/maintenance').catch(() => mock.maintenanceRequests as any); }
}

export const api = new ApiService();

