import React, { useState, useEffect } from 'react';
import { api } from '../apiService';
import { Property } from '../types';

const Properties: React.FC = () => {
  const [propertyList, setPropertyList] = useState<Property[]>([]);
  const [loading, setLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingProperty, setEditingProperty] = useState<Property | null>(null);

  const [formData, setFormData] = useState<Property>({
    id: '',
    name: '',
    address: '',
    type: 'Apartment',
    status: 'Vacant',
    price: 0,
    rooms: 0,
    kitchens: 0,
    bathrooms: 0,
    image: 'https://images.unsplash.com/photo-1560518883-ce09059eeffa?auto=format&fit=crop&w=800&q=80'
  });

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    try {
      const data = await api.getProperties();
      setPropertyList(data);
    } catch (error) {
      console.error("Fetch failed:", error);
    }
    setLoading(false);
  };

  const handleOpenModal = (property?: Property) => {
    if (property) {
      setEditingProperty(property);
      setFormData(property);
    } else {
      setEditingProperty(null);
      setFormData({
        id: Math.random().toString(36).substr(2, 9),
        name: '',
        address: '',
        type: 'Apartment',
        status: 'Vacant',
        price: 0,
        rooms: 0,
        kitchens: 0,
        bathrooms: 0,
        image: 'https://images.unsplash.com/photo-1560518883-ce09059eeffa?auto=format&fit=crop&w=800&q=80'
      });
    }
    setIsModalOpen(true);
  };

  const handleDelete = async (id: string) => {
    if (window.confirm('Delete this property?')) {
      try {
        await api.deleteProperty(id);
        setPropertyList(prev => prev.filter(p => p.id !== id));
      } catch (e) {
        alert("Delete failed. Ensure server is running.");
      }
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      if (editingProperty) {
        const updated = await api.updateProperty(editingProperty.id, formData);
        setPropertyList(prev => prev.map(p => p.id === updated.id ? updated : p));
      } else {
        const created = await api.createProperty(formData);
        setPropertyList(prev => [created, ...prev]);
      }
      setIsModalOpen(false);
    } catch (e) {
      alert("Save failed.");
    }
  };

  if (loading) return (
    <div className="p-8 flex items-center justify-center h-full">
      <div className="flex flex-col items-center gap-4">
        <i className="fa-solid fa-circle-notch fa-spin text-3xl text-teal-500"></i>
        <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">Syncing Database...</p>
      </div>
    </div>
  );

  return (
    <div className="p-8 space-y-10 animate-in fade-in duration-700 max-w-7xl mx-auto">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 border-b border-slate-100 pb-8">
        <div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">Real Estate Inventory</h1>
          <p className="text-slate-500 font-medium mt-1">Full CRUD management for Mogadishu properties.</p>
        </div>
        <button 
          onClick={() => handleOpenModal()}
          className="px-8 py-4 bg-teal-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-teal-600/20 hover:bg-teal-700 active:scale-95 transition-all flex items-center gap-2"
        >
          <i className="fa-solid fa-plus"></i>
          Add Property
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {propertyList.map(property => (
          <div key={property.id} className="bg-white rounded-[2.5rem] overflow-hidden shadow-sm border border-slate-100 group hover:shadow-2xl transition-all duration-500">
            <div className="h-64 overflow-hidden relative">
              <img src={property.image} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" alt={property.name} />
              <div className="absolute top-4 left-4">
                 <span className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest backdrop-blur-md border ${property.status === 'Vacant' ? 'bg-emerald-500/90 text-white border-emerald-400' : 'bg-rose-500/90 text-white border-rose-400'}`}>
                   {property.status}
                 </span>
              </div>
              <div className="absolute bottom-4 left-4 right-4 bg-black/30 backdrop-blur-md p-3 rounded-2xl border border-white/10 flex justify-between items-center text-white">
                 <span className="text-xl font-black">${property.price.toLocaleString()}</span>
                 <span className="text-[8px] font-black uppercase tracking-widest">MONTHLY</span>
              </div>
            </div>

            <div className="p-6">
              <div className="flex justify-between items-start mb-4">
                <div>
                  <h3 className="text-lg font-black text-slate-900">{property.name}</h3>
                  <p className="text-xs text-slate-400 font-medium flex items-center gap-1.5 mt-1">
                    <i className="fa-solid fa-location-dot text-teal-500"></i> {property.address}
                  </p>
                </div>
              </div>

              <div className="grid grid-cols-3 gap-3 py-4 border-y border-slate-50 my-4">
                <div className="text-center">
                  <p className="text-[10px] font-black text-slate-900 leading-none">{property.rooms}</p>
                  <p className="text-[8px] font-bold text-slate-400 uppercase mt-1">Rooms</p>
                </div>
                <div className="text-center border-x border-slate-50">
                  <p className="text-[10px] font-black text-slate-900 leading-none">{property.kitchens}</p>
                  <p className="text-[8px] font-bold text-slate-400 uppercase mt-1">Kitchen</p>
                </div>
                <div className="text-center">
                  <p className="text-[10px] font-black text-slate-900 leading-none">{property.bathrooms}</p>
                  <p className="text-[8px] font-bold text-slate-400 uppercase mt-1">Bath</p>
                </div>
              </div>

              <div className="flex gap-2">
                <button onClick={() => handleOpenModal(property)} className="flex-1 py-3 bg-slate-900 text-white rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-teal-600 transition-all">
                  Edit
                </button>
                <button onClick={() => handleDelete(property.id)} className="px-4 py-3 border border-slate-100 rounded-xl text-slate-400 hover:text-rose-500 transition-all">
                  <i className="fa-solid fa-trash-can"></i>
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => setIsModalOpen(false)}></div>
          <div className="bg-white rounded-[2rem] w-full max-w-lg relative z-10 shadow-2xl animate-in zoom-in duration-300 overflow-hidden">
            <div className="p-6 border-b border-slate-50 flex justify-between items-center bg-slate-50/50">
              <h2 className="text-xl font-black text-slate-900">{editingProperty ? 'Edit Property' : 'Add Property'}</h2>
              <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-900"><i className="fa-solid fa-xmark"></i></button>
            </div>
            <form onSubmit={handleSubmit} className="p-6 space-y-4 max-h-[80vh] overflow-y-auto custom-scrollbar">
              <div className="space-y-1">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Name</label>
                <input required value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl text-sm font-bold focus:ring-2 focus:ring-teal-500 outline-none" placeholder="Property Name" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Price ($)</label>
                  <input type="number" required value={formData.price} onChange={e => setFormData({...formData, price: Number(e.target.value)})} className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl text-sm font-bold focus:ring-2 focus:ring-teal-500 outline-none" />
                </div>
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Type</label>
