  private async request<T>(endpoint: string, options?: RequestInit): Promise<T> {
    try {
      const response = await fetch(`${BASE_URL}${endpoint}`, {
        ...options,
        headers: {
          'Content-Type': 'application/json',
          ...options?.headers,
        },
      });

      if (!response.ok) {
        const errorData = await response.json().catch(() => ({}));
        throw new Error(errorData.message || `API Error: ${response.status}`);
      }

      return await response.json();
    } catch (error) {
      console.error(`Error requesting ${endpoint}:`, error);
      throw error;
    }
  }

  // Properties CRUD
  async getProperties(): Promise<Property[]> {
    return this.request<Property[]>('/properties').catch(() => {
      const data = localStorage.getItem('eliteestate_properties');
      return data ? JSON.parse(data) : [];
    });
  }

  async createProperty(property: Property): Promise<Property> {
    const response = await this.request<Property>('/properties', {
      method: 'POST',
      body: JSON.stringify(property),
    });
    // Sync local storage as fallback
    const local = await this.getProperties();
    localStorage.setItem('eliteestate_properties', JSON.stringify([response, ...local]));
    return response;
  }

  async updateProperty(id: string, property: Property): Promise<Property> {
    const response = await this.request<Property>(`/properties/${id}`, {
      method: 'PUT',
      body: JSON.stringify(property),
    });
    const local = await this.getProperties();
    localStorage.setItem('eliteestate_properties', JSON.stringify(local.map(p => p.id === id ? response : p)));
    return response;
  }

  async deleteProperty(id: string): Promise<void> {
    await this.request(`/properties/${id}`, { method: 'DELETE' });
    const local = await this.getProperties();
    localStorage.setItem('eliteestate_properties', JSON.stringify(local.filter(p => p.id !== id)));
  }

  // Other methods
  async getTenants(): Promise<Tenant[]> {
    return this.request<Tenant[]>('/tenants').catch(() => []);
  }

  async getMaintenance(): Promise<MaintenanceRequest[]> {
    return this.request<MaintenanceRequest[]>('/maintenance').catch(() => []);
  }

  async getSales(): Promise<Sale[]> {
    return this.request<Sale[]>('/sales').catch(() => []);
  }

  async getRents(): Promise<RentRecord[]> {
    return this.request<RentRecord[]>('/rents').catch(() => []);
  }

  async getFinancials(): Promise<FinancialRecord[]> {
    return this.request<FinancialRecord[]>('/financials').catch(() => []);
  }
}

