import { Property, Tenant, Sale, RentRecord, MaintenanceRequest, FinancialRecord } from './types';
import * as mock from './mockData';

const BASE_URL = 'http://localhost:5000/api';

class ApiService {
  private async request<T>(endpoint: string, options?: RequestInit): Promise<T> {
    try {
      const response = await fetch(`${BASE_URL}${endpoint}`, {
        ...options,
        headers: {
          'Content-Type': 'application/json',
          ...options?.headers,
        },
      });

      if (!response.ok) {
        const errorBody = await response.json().catch(() => ({}));
        throw new Error(errorBody.message || `API Error: ${response.status}`);
      }
      return await response.json();
    } catch (error) {
      console.error(`API Request failed for ${endpoint}:`, error);

      // Local fallback logic for demo/offline purposes
      if (endpoint === '/properties' && (!options || options.method === 'GET')) {
        const local = localStorage.getItem('eliteestate_properties');
        return local ? JSON.parse(local) : mock.properties as any;
      }

      throw error;
    }
  }

  // Properties CRUD - Fixed and Synchronized
  async getProperties(): Promise<Property[]> {
    return this.request<Property[]>('/properties');
  }

  async createProperty(property: Property): Promise<Property> {
    const created = await this.request<Property>('/properties', { 
      method: 'POST', 
      body: JSON.stringify(property) 
    });
    // Sync with local storage for consistency
    const current = await this.getProperties();
    localStorage.setItem('eliteestate_properties', JSON.stringify([created, ...current]));
    return created;
  }

  async updateProperty(id: string, property: Property): Promise<Property> {
    const updated = await this.request<Property>(`/properties/${id}`, { 
      method: 'PUT', 
      body: JSON.stringify(property) 
    });
    const current = await this.getProperties();
    localStorage.setItem('eliteestate_properties', JSON.stringify(current.map(p => p.id === id ? updated : p)));
    return updated;
  }

  async deleteProperty(id: string): Promise<void> {
    await this.request<void>(`/properties/${id}`, { method: 'DELETE' });
    const current = await this.getProperties();
    localStorage.setItem('eliteestate_properties', JSON.stringify(current.filter(p => p.id !== id)));
  }

  // Sales
  async getSales(): Promise<Sale[]> { return this.request<Sale[]>('/sales').catch(() => mock.sales as any); }
  async createSale(sale: Sale): Promise<Sale> { return this.request<Sale>('/sales', { method: 'POST', body: JSON.stringify(sale) }); }
  async deleteSale(id: string): Promise<void> { return this.request<void>(`/sales/${id}`, { method: 'DELETE' }); }

  // Financials
  async getFinancials(): Promise<FinancialRecord[]> { return this.request<FinancialRecord[]>('/financials').catch(() => [] as any); }
  async createFinancial(record: FinancialRecord): Promise<FinancialRecord> { return this.request<FinancialRecord>('/financials', { method: 'POST', body: JSON.stringify(record) }); }
  async deleteFinancial(id: string): Promise<void> { return this.request<void>(`/financials/${id}`, { method: 'DELETE' }); }

  // Others
  async getTenants(): Promise<Tenant[]> { return this.request<Tenant[]>('/tenants').catch(() => mock.tenants as any); }
  async getMaintenance(): Promise<MaintenanceRequest[]> { return this.request<MaintenanceRequest[]>('/maintenance').catch(() => mock.maintenanceRequests as any); }
}

