              <div className="space-y-1">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Location Address</label>
                <input required value={formData.address} onChange={e => setFormData({...formData, address: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold focus:ring-2 focus:ring-teal-500 outline-none" placeholder="District, Mogadishu" />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Monthly Rent ($)</label>
                  <input type="number" required value={formData.price} onChange={e => setFormData({...formData, price: Number(e.target.value)})} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold focus:ring-2 focus:ring-teal-500 outline-none" />
                </div>
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Category</label>
                  <select value={formData.type} onChange={e => setFormData({...formData, type: e.target.value as any})} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold focus:ring-2 focus:ring-teal-500 outline-none">
                    <option value="Apartment">Apartment</option>
                    <option value="House">House</option>
                    <option value="Hotel">Hotel</option>
                    <option value="Commercial">Commercial</option>
                  </select>
                </div>
              </div>

              <div className="grid grid-cols-3 gap-4">
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Rooms</label>
                  <input type="number" value={formData.rooms} onChange={e => setFormData({...formData, rooms: Number(e.target.value)})} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold focus:ring-2 focus:ring-teal-500 outline-none" />
                </div>
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Kitchens</label>
                  <input type="number" value={formData.kitchens} onChange={e => setFormData({...formData, kitchens: Number(e.target.value)})} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold focus:ring-2 focus:ring-teal-500 outline-none" />
                </div>
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Bath</label>
                  <input type="number" value={formData.bathrooms} onChange={e => setFormData({...formData, bathrooms: Number(e.target.value)})} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold focus:ring-2 focus:ring-teal-500 outline-none" />
                </div>
              </div>

              <div className="space-y-1">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Lease Status</label>
                <div className="flex gap-2 p-1 bg-slate-100 rounded-xl">
                  {['Vacant', 'Occupied', 'Under Maintenance'].map(s => (
                    <button 
                      key={s} 
                      type="button" 
                      onClick={() => setFormData({...formData, status: s as any})} 
                      className={`flex-1 py-2.5 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all ${formData.status === s ? 'bg-white text-teal-600 shadow-sm' : 'text-slate-400'}`}
                    >
                      {s}
                    </button>
                  ))}
                </div>
              </div>

              <button 
                type="submit" 
                disabled={isSaving}
                className={`w-full py-4 mt-2 text-white rounded-xl font-black text-[10px] uppercase tracking-widest shadow-xl transition-all active:scale-95 flex items-center justify-center gap-2 ${isSaving ? 'bg-slate-400' : 'bg-teal-600 hover:bg-teal-700 shadow-teal-600/20'}`}
              >
                {isSaving ? (
                  <>
                    <i className="fa-solid fa-circle-notch fa-spin"></i> Processing...
                  </>
                ) : (
                  <>
                    <i className="fa-solid fa-cloud-arrow-up"></i> {editingProperty ? 'Update Portfolio' : 'Publish Property'}
                  </>
                )}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Properties;

import React, { useState, useEffect, useRef } from 'react';
import { api } from '../apiService';
import { Property } from '../types';

const Properties: React.FC = () => {
  const [propertyList, setPropertyList] = useState<Property[]>([]);
  const [loading, setLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingProperty, setEditingProperty] = useState<Property | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [formData, setFormData] = useState<Property>({
    id: '',
    name: '',
    address: '',
    type: 'Apartment',
    status: 'Vacant',
    price: 0,
    rooms: 0,
    kitchens: 0,
    bathrooms: 0,
    image: 'https://images.unsplash.com/photo-1560518883-ce09059eeffa?auto=format&fit=crop&w=800&q=80'
  });

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    try {
      const data = await api.getProperties();
      // Ensure we have an array even if API fails or returns null
      setPropertyList(Array.isArray(data) ? data : []);
    } catch (error) {
      console.error("Fetch failed:", error);
    }
    setLoading(false);
  };

  const handleOpenModal = (property?: Property) => {
    if (property) {
      setEditingProperty(property);
      setFormData({ ...property });
    } else {
      setEditingProperty(null);
      setFormData({
        id: 'PRP-' + Math.random().toString(36).substr(2, 6).toUpperCase(),
        name: '',
        address: '',
        type: 'Apartment',
        status: 'Vacant',
        price: 0,
        rooms: 0,
        kitchens: 0,
        bathrooms: 0,
        image: 'https://images.unsplash.com/photo-1560518883-ce09059eeffa?auto=format&fit=crop&w=800&q=80'
      });
    }
    setIsModalOpen(true);
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setFormData(prev => ({ ...prev, image: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSaving(true);
    try {
      if (editingProperty) {
        const updated = await api.updateProperty(editingProperty.id, formData);
        setPropertyList(prev => prev.map(p => p.id === updated.id ? updated : p));
      } else {
        const created = await api.createProperty(formData);
        setPropertyList(prev => [created, ...prev]);
      }
      setIsModalOpen(false);
    } catch (error) {
      console.error("Save error:", error);
      alert("Waan ka xumahay, xogta lama keydin karo. Fadlan hubi in server-ka uu shaqaynayo.");
    } finally {
      setIsSaving(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (window.confirm('Ma hubtaa inaad tirtirto gurigan?')) {
      try {
        await api.deleteProperty(id);
        setPropertyList(prev => prev.filter(p => p.id !== id));
      } catch (e) {
        alert("Tirtiriddu ma guulaysan.");
      }
    }
  };

  if (loading) return (
    <div className="p-10 flex flex-col items-center justify-center gap-4 h-full">
      <i className="fa-solid fa-spinner fa-spin text-4xl text-teal-600"></i>
      <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">Loading Properties...</p>
    </div>
  );

  return (
    <div className="p-8 space-y-10 animate-in fade-in duration-700 max-w-7xl mx-auto">
      {/* Header Section */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 border-b border-slate-100 pb-8">
        <div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">Properties Inventory</h1>
          <p className="text-slate-500 font-medium mt-1">Full management for Mogadishu real estate assets.</p>
        </div>
        <button 
          onClick={() => handleOpenModal()}
          className="px-8 py-4 bg-teal-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-teal-600/20 hover:bg-teal-700 active:scale-95 transition-all flex items-center gap-2"
        >
          <i className="fa-solid fa-plus"></i> Add Property
        </button>
      </div>

      {/* Property Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {propertyList.length > 0 ? propertyList.map(property => (
          <div key={property.id} className="bg-white rounded-[2.5rem] overflow-hidden shadow-sm border border-slate-100 group hover:shadow-2xl transition-all duration-500">
            <div className="h-64 overflow-hidden relative">
              <img src={property.image} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" alt={property.name} />
              <div className="absolute top-4 left-4">
                 <span className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest backdrop-blur-md border ${property.status === 'Vacant' ? 'bg-emerald-500/90 text-white border-emerald-400' : property.status === 'Occupied' ? 'bg-rose-500/90 text-white border-rose-400' : 'bg-amber-500/90 text-white border-amber-400'}`}>
                   {property.status}
                 </span>
              </div>
              <div className="absolute bottom-4 left-4 right-4 bg-black/30 backdrop-blur-md p-3 rounded-2xl border border-white/10 flex justify-between items-center text-white">
                 <span className="text-xl font-black">${property.price.toLocaleString()}</span>
                 <span className="text-[8px] font-black uppercase tracking-widest">PER MONTH</span>
              </div>
            </div>

            <div className="p-6">
              <h3 className="text-lg font-black text-slate-900 truncate">{property.name}</h3>
              <p className="text-xs text-slate-400 font-medium flex items-center gap-1.5 mt-1">
                <i className="fa-solid fa-location-dot text-teal-500"></i> {property.address}
              </p>

              <div className="grid grid-cols-3 gap-3 py-4 border-y border-slate-50 my-4">
                <div className="text-center">
                  <p className="text-[10px] font-black text-slate-900">{property.rooms}</p>
                  <p className="text-[8px] font-bold text-slate-400 uppercase mt-1">Rooms</p>
                </div>
                <div className="text-center border-x border-slate-50">
                  <p className="text-[10px] font-black text-slate-900">{property.kitchens}</p>
                  <p className="text-[8px] font-bold text-slate-400 uppercase mt-1">Kitchen</p>
                </div>
                <div className="text-center">
                  <p className="text-[10px] font-black text-slate-900">{property.bathrooms}</p>
                  <p className="text-[8px] font-bold text-slate-400 uppercase mt-1">Bath</p>
                </div>
              </div>

              <div className="flex gap-2">
                <button onClick={() => handleOpenModal(property)} className="flex-1 py-3 bg-slate-900 text-white rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-teal-600 transition-all">
                  Edit
                </button>
                <button onClick={() => handleDelete(property.id)} className="px-4 py-3 border border-slate-100 rounded-xl text-slate-400 hover:text-rose-500 transition-all">
                  <i className="fa-solid fa-trash-can"></i>
                </button>
              </div>
            </div>
          </div>
        )) : (
          <div className="col-span-full py-20 text-center bg-white rounded-[2.5rem] border-2 border-dashed border-slate-100">
             <i className="fa-solid fa-building-circle-exclamation text-4xl text-slate-200 mb-4"></i>
             <p className="text-slate-400 font-bold uppercase text-[10px] tracking-widest">Ma jiraan guryo la diwaan geliyay</p>
          </div>
        )}
      </div>

      {/* Add/Edit Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => !isSaving && setIsModalOpen(false)}></div>
          <div className="bg-white rounded-[2rem] w-full max-w-lg relative z-10 shadow-2xl animate-in zoom-in duration-300 overflow-hidden border border-slate-100">
            <div className="p-6 border-b border-slate-50 flex justify-between items-center bg-slate-50/50">
              <h2 className="text-xl font-black text-slate-900">{editingProperty ? 'Edit Property Details' : 'Add New Property'}</h2>
              <button disabled={isSaving} onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-900 transition-colors">
                <i className="fa-solid fa-xmark text-lg"></i>
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-6 space-y-4 max-h-[85vh] overflow-y-auto custom-scrollbar">
              {/* Image Upload UI */}
              <div className="space-y-2">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Property Visual</label>
                <div className="flex items-center gap-4">
                  <div className="w-24 h-24 rounded-2xl overflow-hidden border-2 border-slate-100 bg-slate-50 shadow-inner relative group">
                    <img src={formData.image} alt="Preview" className="w-full h-full object-cover" />
                    <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center cursor-pointer" onClick={() => fileInputRef.current?.click()}>
                       <i className="fa-solid fa-camera text-white"></i>
                    </div>
                  </div>
                  <div className="space-y-2">
                    <button 
                      type="button" 
                      onClick={() => fileInputRef.current?.click()}
                      className="px-4 py-2.5 bg-slate-100 text-slate-600 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-slate-200 transition-all"
                    >
                      Choose Photo
                    </button>
                    <p className="text-[8px] text-slate-400 font-bold uppercase tracking-wider">JPG or PNG allowed.</p>
                  </div>
                  <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleImageChange} />
                </div>
              </div>

              <div className="space-y-1">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Name</label>
                <input required value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold focus:ring-2 focus:ring-teal-500 outline-none transition-all" placeholder="e.g. Somali Golden House" />
              </div>

              <div className="space-y-1">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Address</label>
                <input required value={formData.address} onChange={e => setFormData({...formData, address: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold focus:ring-2 focus:ring-teal-500 outline-none transition-all" placeholder="e.g. Hodan, Mogadishu" />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Monthly Rent ($)</label>
                  <input type="number" required value={formData.price} onChange={e => setFormData({...formData, price: Number(e.target.value)})} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold focus:ring-2 focus:ring-teal-500 outline-none" />
                </div>
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Category</label>
                  <select value={formData.type} onChange={e => setFormData({...formData, type: e.target.value as any})} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold focus:ring-2 focus:ring-teal-500 outline-none">
                    <option value="Apartment">Apartment</option>
                    <option value="House">House</option>
                    <option value="Hotel">Hotel</option>
                    <option value="Commercial">Commercial</option>
                  </select>
                </div>
              </div>

              <div className="grid grid-cols-3 gap-4">
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Rooms</label>
                  <input type="number" value={formData.rooms} onChange={e => setFormData({...formData, rooms: Number(e.target.value)})} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold focus:ring-2 focus:ring-teal-500 outline-none" />
                </div>
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Kitchen</label>
                  <input type="number" value={formData.kitchens} onChange={e => setFormData({...formData, kitchens: Number(e.target.value)})} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold focus:ring-2 focus:ring-teal-500 outline-none" />
                </div>
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Bath</label>
                  <input type="number" value={formData.bathrooms} onChange={e => setFormData({...formData, bathrooms: Number(e.target.value)})} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold focus:ring-2 focus:ring-teal-500 outline-none" />
                </div>
              </div>

              <div className="space-y-1">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Status</label>
                <div className="flex gap-2 p-1 bg-slate-100 rounded-xl">
                  {['Vacant', 'Occupied', 'Under Maintenance'].map(s => (
                    <button 
                      key={s} 
                      type="button" 
                      onClick={() => setFormData({...formData, status: s as any})} 
                      className={`flex-1 py-2.5 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all ${formData.status === s ? 'bg-white text-teal-600 shadow-sm' : 'text-slate-400'}`}
                    >
                      {s}
                    </button>
                  ))}
                </div>
              </div>

              <button 
                type="submit" 
                disabled={isSaving}
                className={`w-full py-4 mt-2 text-white rounded-xl font-black text-[10px] uppercase tracking-widest shadow-xl transition-all active:scale-95 flex items-center justify-center gap-2 ${isSaving ? 'bg-slate-400' : 'bg-teal-600 hover:bg-teal-700 shadow-teal-600/20'}`}
              >
                {isSaving ? (
                  <>
                    <i className="fa-solid fa-circle-notch fa-spin"></i> Processing...
                  </>
                ) : (
                  <>
                    <i className="fa-solid fa-cloud-arrow-up"></i> {editingProperty ? 'Update Property' : 'Publish Property'}
                  </>
                )}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
