import { Property, Tenant, Sale, RentRecord, MaintenanceRequest, FinancialRecord } from './types';
import * as mock from './mockData';

const BASE_URL = 'http://localhost:5000/api';

class ApiService {
  private getLocal<T>(key: string, fallback: T[]): T[] {
    try {
      const data = localStorage.getItem(`elite_${key}`);
      return data ? JSON.parse(data) : fallback;
    } catch (e) {
      return fallback;
    }
  }

  private setLocal<T>(key: string, data: T[]): void {
    try {
      localStorage.setItem(`elite_${key}`, JSON.stringify(data));
    } catch (e) {
      console.warn('Storage limit reached');
    }
  }

  private async safeRequest<T>(endpoint: string, options: RequestInit, localKey: string, fallbackData: any): Promise<T> {
    try {
      const response = await fetch(`${BASE_URL}${endpoint}`, {
        ...options,
        headers: { 'Content-Type': 'application/json', ...options.headers },
      });
      if (!response.ok) throw new Error('Server Error');
      const data = await response.json();

      // If it was a GET request, update our local cache
      if (!options.method || options.method === 'GET') {
        this.setLocal(localKey, data);
      }
      return data;
    } catch (error) {
      // Logic for offline fallback
      const local = this.getLocal(localKey, fallbackData);

      if (options.method === 'POST') {
        const newItem = JSON.parse(options.body as string);
        const updated = [newItem, ...local];
        this.setLocal(localKey, updated);
        return newItem;
      }

      if (options.method === 'PUT') {
        const updatedItem = JSON.parse(options.body as string);
        const id = endpoint.split('/').pop();
        const updated = local.map((item: any) => (item.id === id || item._id === id) ? updatedItem : item);
        this.setLocal(localKey, updated);
        return updatedItem;
      }

      if (options.method === 'DELETE') {
        const id = endpoint.split('/').pop();
        const updated = local.filter((item: any) => item.id !== id && item._id !== id);
        this.setLocal(localKey, updated);
        return {} as T;
      }

      return local as T;
    }
  }

  // Properties
  async getProperties(): Promise<Property[]> {
    return this.safeRequest<Property[]>('/properties', { method: 'GET' }, 'properties', mock.properties);
  }

  async createProperty(property: Property): Promise<Property> {
    return this.safeRequest<Property>('/properties', { method: 'POST', body: JSON.stringify(property) }, 'properties', mock.properties);
  }

  async updateProperty(id: string, property: Property): Promise<Property> {
    return this.safeRequest<Property>(`/properties/${id}`, { method: 'PUT', body: JSON.stringify(property) }, 'properties', mock.properties);
  }

  async deleteProperty(id: string): Promise<void> {
    await this.safeRequest<void>(`/properties/${id}`, { method: 'DELETE' }, 'properties', mock.properties);
  }

  // Sales
  async getSales(): Promise<Sale[]> {
    return this.safeRequest<Sale[]>('/sales', { method: 'GET' }, 'sales', mock.sales);
  }

  async createSale(sale: Sale): Promise<Sale> {
    return this.safeRequest<Sale>('/sales', { method: 'POST', body: JSON.stringify(sale) }, 'sales', mock.sales);
  }

  async deleteSale(id: string): Promise<void> {
    await this.safeRequest<void>(`/sales/${id}`, { method: 'DELETE' }, 'sales', mock.sales);
  }

  // Financials
  async getFinancials(): Promise<FinancialRecord[]> {
    return this.safeRequest<FinancialRecord[]>('/financials', { method: 'GET' }, 'financials', []);
  }

  async createFinancial(record: FinancialRecord): Promise<FinancialRecord> {
    return this.safeRequest<FinancialRecord>('/financials', { method: 'POST', body: JSON.stringify(record) }, 'financials', []);
  }

  async deleteFinancial(id: string): Promise<void> {
    await this.safeRequest<void>(`/financials/${id}`, { method: 'DELETE' }, 'financials', []);
  }

  // Tenants & Maintenance (ReadOnly/Mock for now)
  async getTenants(): Promise<Tenant[]> {
    return this.safeRequest<Tenant[]>('/tenants', { method: 'GET' }, 'tenants', mock.tenants);
  }

  async getMaintenance(): Promise<MaintenanceRequest[]> {
    return this.safeRequest<MaintenanceRequest[]>('/maintenance', { method: 'GET' }, 'maintenance', mock.maintenanceRequests);
  }
}

