const Rents: React.FC = () => {
  const [rentList, setRentList] = useState<RentRecord[]>([]);
  const [properties, setProperties] = useState<Property[]>([]);
  const [loading, setLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingRent, setEditingRent] = useState<RentRecord | null>(null);

  const [formData, setFormData] = useState<Partial<RentRecord>>({
    propertyId: '',
    tenantName: '',
    amount: 0,
    dueDate: new Date().toISOString().split('T')[0],
    status: 'Pending'
  });

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    try {
      const [rData, pData] = await Promise.all([
        api.getRents(),
        api.getProperties()
      ]);
      setRentList(rData || []);
      setProperties(pData || []);

      if (pData && pData.length > 0 && !formData.propertyId) {
        setFormData(prev => ({ 
          ...prev, 
          propertyId: pData[0].id, 
          amount: pData[0].price 
        }));
      }
    } catch (e) {
      console.error("Failed to load rent data:", e);
    }
    setLoading(false);
  };

  const getProperty = (id: string) => properties.find(p => p.id === id);

  const handleOpenModal = (rent?: RentRecord) => {
    if (rent) {
      setEditingRent(rent);
      setFormData(rent);
    } else {
      setEditingRent(null);
      setFormData({
        propertyId: properties[0]?.id || '',
        tenantName: '',
        amount: properties[0]?.price || 0,
        dueDate: new Date().toISOString().split('T')[0],
        status: 'Pending'
      });
    }
    setIsModalOpen(true);
  };

