          <h1 className="text-3xl font-black text-slate-900 tracking-tight">Maamulka Kirada</h1>
          <p className="text-slate-500 font-medium">La soco lacagaha kirada ee dhismayaasha.</p>
        </div>
        <button 
          onClick={() => handleOpenModal()}
          className="px-6 py-3 bg-teal-600 text-white rounded-2xl text-xs font-black uppercase tracking-widest hover:bg-teal-700 transition-all shadow-lg shadow-teal-600/20 active:scale-95 flex items-center gap-2"
        >
          <i className="fa-solid fa-file-invoice-dollar"></i>
          Kudar Kirada
        </button>
      </div>

      <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead>
            <tr className="border-b border-slate-100 bg-slate-50/50">
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Asset</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Tenant</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Amount</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Status</th>
              <th className="px-8 py-5 text-right"></th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {rentList.map(rent => {
              const property = getProperty(rent.propertyId);
              return (
                <tr key={rent.id} className="hover:bg-slate-50/80 transition-colors group">
                  <td className="px-8 py-5">
                    <p className="font-bold text-slate-900">{property?.name || 'Asset'}</p>
                  </td>
                  <td className="px-8 py-5 font-semibold text-slate-700">{rent.tenantName}</td>
                  <td className="px-8 py-5 text-teal-600 font-black">${rent.amount.toLocaleString()}</td>
                  <td className="px-8 py-5">
                    <span className={`px-3 py-1 rounded-lg text-[10px] font-black uppercase tracking-widest ${
                      rent.status === 'Paid' ? 'bg-emerald-50 text-emerald-600' : 'bg-amber-50 text-amber-600'
