            <div className="p-8 border-b border-slate-50">
              <h2 className="text-2xl font-black text-slate-900 tracking-tight">Rent Record</h2>
            </div>
            <form onSubmit={handleSubmit} className="p-8 space-y-6">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Select Building</label>
                <select required value={formData.propertyId} onChange={(e) => {
                  const prop = properties.find(p => p.id === e.target.value);
                  setFormData({ ...formData, propertyId: e.target.value, amount: prop?.price || 0 });
                }} className="w-full px-5 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl text-sm font-semibold focus:ring-2 focus:ring-teal-500 outline-none transition-all">
                  {properties.map(p => <option key={p.id} value={p.id}>{p.name} (${p.price})</option>)}
                </select>
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Tenant Name</label>
                <input required value={formData.tenantName} onChange={(e) => setFormData({ ...formData, tenantName: e.target.value })} className="w-full px-5 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl text-sm font-semibold focus:ring-2 focus:ring-teal-500 outline-none" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Amount</label>
                  <input required type="number" value={formData.amount} onChange={(e) => setFormData({ ...formData, amount: Number(e.target.value) })} className="w-full px-5 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl text-sm font-semibold focus:ring-2 focus:ring-teal-500 outline-none" />
