import { Property, Tenant, MaintenanceRequest, Sale, RentRecord, FinancialRecord } from './types';
import * as mock from './mockData';

const BASE_URL = 'http://localhost:5000/api';

class ApiService {
  private getLocal<T>(key: string, fallback: T[]): T[] {
    try {
      const data = localStorage.getItem(`eliteestate_${key}`);
      return data ? JSON.parse(data) : fallback;
    } catch (e) {
      return fallback;
    }
  }

  private setLocal<T>(key: string, data: T[]): void {
    try {
      localStorage.setItem(`eliteestate_${key}`, JSON.stringify(data));
    } catch (e) {
      console.warn('Storage limit reached');
    }
  }

  private async safeRequest<T>(
    endpoint: string, 
    method: string, 
    localKey: string, 
    fallback: any, 
    body?: any
  ): Promise<T> {
    try {
      const response = await fetch(`${BASE_URL}${endpoint}`, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: body ? JSON.stringify(body) : undefined,
        signal: AbortSignal.timeout(1500) 
      });

      if (response.ok) {
        const data = await response.json();
        if (method === 'GET') this.setLocal(localKey, data);
        return data;
      }
      throw new Error('Server issues');
    } catch (e) {
      const current = this.getLocal(localKey, fallback);

      if (method === 'POST' && body) {
        const updated = [body, ...current];
        this.setLocal(localKey, updated);
        return body;
      }

      if (method === 'PUT' && body) {
        const updated = current.map((item: any) => (item.id === body.id || item._id === body.id) ? body : item);
        this.setLocal(localKey, updated);
        return body;
      }

      if (method === 'DELETE') {
        const id = endpoint.split('/').pop();
        const updated = current.filter((item: any) => item.id !== id && item._id !== id);
        this.setLocal(localKey, updated);
        return {} as T;
      }

      return current as unknown as T;
    }
  }

  // Properties
  async getProperties(): Promise<Property[]> {
    return this.safeRequest<Property[]>('/properties', 'GET', 'properties', mock.properties);
  }
  async createProperty(property: Property): Promise<Property> {
    return this.safeRequest<Property>('/properties', 'POST', 'properties', mock.properties, property);
  }
  async updateProperty(id: string, property: Property): Promise<Property> {
    return this.safeRequest<Property>(`/properties/${id}`, 'PUT', 'properties', mock.properties, property);
  }
  async deleteProperty(id: string): Promise<void> {
    await this.safeRequest<void>(`/properties/${id}`, 'DELETE', 'properties', mock.properties);
  }

  // Tenants
  async getTenants(): Promise<Tenant[]> {
    return this.safeRequest<Tenant[]>('/tenants', 'GET', 'tenants', mock.tenants);
  }
  async createTenant(tenant: Tenant): Promise<Tenant> {
    return this.safeRequest<Tenant>('/tenants', 'POST', 'tenants', mock.tenants, tenant);
  }
  async updateTenant(id: string, tenant: Tenant): Promise<Tenant> {
    return this.safeRequest<Tenant>(`/tenants/${id}`, 'PUT', 'tenants', mock.tenants, tenant);
  }

  // Rents
  async getRents(): Promise<RentRecord[]> {
    return this.safeRequest<RentRecord[]>('/rents', 'GET', 'rents', []);
  }
  async createRent(rent: RentRecord): Promise<RentRecord> {
    return this.safeRequest<RentRecord>('/rents', 'POST', 'rents', [], rent);
  }
  async updateRent(id: string, rent: RentRecord): Promise<RentRecord> {
    return this.safeRequest<RentRecord>(`/rents/${id}`, 'PUT', 'rents', [], rent);
  }

  // Sales
  async getSales(): Promise<Sale[]> {
    return this.safeRequest<Sale[]>('/sales', 'GET', 'sales', mock.sales);
  }
  async createSale(sale: Sale): Promise<Sale> {
    return this.safeRequest<Sale>('/sales', 'POST', 'sales', mock.sales, sale);
  }
  async deleteSale(id: string): Promise<void> {
    await this.safeRequest<void>(`/sales/${id}`, 'DELETE', 'sales', mock.sales);
  }

  // Maintenance
  async getMaintenance(): Promise<MaintenanceRequest[]> {
    return this.safeRequest<MaintenanceRequest[]>('/maintenance', 'GET', 'maintenance', mock.maintenanceRequests);
  }
  async createMaintenance(req: MaintenanceRequest): Promise<MaintenanceRequest> {
    return this.safeRequest<MaintenanceRequest>('/maintenance', 'POST', 'maintenance', mock.maintenanceRequests, req);
  }
  async updateMaintenance(id: string, req: MaintenanceRequest): Promise<MaintenanceRequest> {
    return this.safeRequest<MaintenanceRequest>(`/maintenance/${id}`, 'PUT', 'maintenance', mock.maintenanceRequests, req);
  }

  // Financials
  async getFinancials(): Promise<FinancialRecord[]> {
    return this.safeRequest<FinancialRecord[]>('/financials', 'GET', 'financials', []);
  }
  async createFinancial(record: FinancialRecord): Promise<FinancialRecord> {
    return this.safeRequest<FinancialRecord>('/financials', 'POST', 'financials', [], record);
  }

  // Added missing deleteFinancial method to resolve the error in Financials page
  async deleteFinancial(id: string): Promise<void> {
    await this.safeRequest<void>(`/financials/${id}`, 'DELETE', 'financials', []);
  }
}

