import React, { useState, useEffect } from 'react';
import { api } from '../apiService';
import { Tenant, Property } from '../types';

const Tenants: React.FC = () => {
  const [tenantList, setTenantList] = useState<Tenant[]>([]);
  const [properties, setProperties] = useState<Property[]>([]);
  const [loading, setLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingTenant, setEditingTenant] = useState<Tenant | null>(null);

  const [formData, setFormData] = useState<Partial<Tenant>>({
    name: '',
    email: '',
    phone: '',
    propertyId: '',
    unit: '',
    leaseStart: new Date().toISOString().split('T')[0],
    leaseEnd: new Date(new Date().setFullYear(new Date().getFullYear() + 1)).toISOString().split('T')[0],
    status: 'Active'
  });

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    try {
      const [tData, pData] = await Promise.all([
        api.getTenants(),
        api.getProperties()
      ]);
      setTenantList(tData || []);
      setProperties(pData || []);

      if (pData && pData.length > 0 && !formData.propertyId) {
        setFormData(prev => ({ ...prev, propertyId: pData[0].id }));
      }
    } catch (error) {
      console.error("Failed to load tenants data:", error);
    }
    setLoading(false);
  };

  const getPropertyName = (id: string) => properties.find(p => p.id === id)?.name || 'Building Not Found';

  const handleOpenModal = (tenant?: Tenant) => {
    if (tenant) {
      setEditingTenant(tenant);
      setFormData(tenant);
    } else {
      setEditingTenant(null);
      setFormData({
        name: '',
        email: '',
        phone: '',
        propertyId: properties[0]?.id || '',
        unit: '',
        leaseStart: new Date().toISOString().split('T')[0],
        leaseEnd: new Date(new Date().setFullYear(new Date().getFullYear() + 1)).toISOString().split('T')[0],
        status: 'Active'
      });
    }
    setIsModalOpen(true);
  };

  const handleDelete = async (id: string) => {
    if (window.confirm('Ma hubtaa inaad tirtirto macmiilkan?')) {
      try {
        await api.deleteTenant(id);
        setTenantList(prev => prev.filter(t => t.id !== id));
      } catch (e) {
        console.error("Delete failed:", e);
      }
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      if (editingTenant) {
        const updated = await api.updateTenant(editingTenant.id, { ...editingTenant, ...formData } as Tenant);
        setTenantList(prev => prev.map(t => t.id === updated.id ? updated : t));
      } else {
        const newTenant: Tenant = {
          ...formData,
          id: 'TEN-' + Math.random().toString(36).substr(2, 6).toUpperCase(),
        } as Tenant;
        const created = await api.createTenant(newTenant);
        setTenantList(prev => [created, ...prev]);
      }
      setIsModalOpen(false);
    } catch (err) {
      console.error(err);
    }
  };

  if (loading) return (
    <div className="p-10 flex flex-col items-center justify-center gap-4 h-full min-h-[400px]">
      <i className="fa-solid fa-spinner fa-spin text-4xl text-teal-600"></i>
      <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">Loading Tenants Board...</p>
    </div>
  );

  return (
    <div className="p-8 space-y-8 animate-in fade-in duration-700">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">Maamulka Macmiisha</h1>
          <p className="text-slate-500 font-medium">Liiska dadka degan guryaha iyo xogtooda kirada.</p>
        </div>
        <button 
          onClick={() => handleOpenModal()}
          className="px-6 py-3 bg-teal-600 text-white rounded-2xl text-xs font-black uppercase tracking-widest hover:bg-teal-700 transition-all shadow-lg shadow-teal-600/20 active:scale-95 flex items-center gap-2"
        >
          <i className="fa-solid fa-user-plus"></i>
          Kudar Macmiil
        </button>
      </div>

      <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead>
            <tr className="border-b border-slate-100 bg-slate-50/50">
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Macmiilka</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Dhismaha & Qaybta</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Xaalada</th>
              <th className="px-8 py-5 text-right"></th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {tenantList.map(tenant => (
              <tr key={tenant.id} className="hover:bg-slate-50/80 transition-colors group">
                <td className="px-8 py-5">
                  <p className="font-bold text-slate-900">{tenant.name}</p>
                  <p className="text-[10px] text-slate-400 font-medium">{tenant.phone}</p>
                </td>
                <td className="px-8 py-5">
                  <p className="text-sm font-bold text-slate-800">{getPropertyName(tenant.propertyId)}</p>
                  <p className="text-slate-400 text-[10px] font-bold uppercase tracking-wider">Unit: {tenant.unit || 'N/A'}</p>
                </td>
                <td className="px-8 py-5">
                  <span className={`inline-flex px-3 py-1 rounded-lg text-[10px] font-black uppercase tracking-widest ${
                    tenant.status === 'Active' ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' : 'bg-rose-50 text-rose-600 border border-rose-100'
                  }`}>
                    {tenant.status}
                  </span>
                </td>
                <td className="px-8 py-5 text-right">
                  <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                    <button onClick={() => handleOpenModal(tenant)} className="w-9 h-9 flex items-center justify-center bg-teal-50 text-teal-600 rounded-xl hover:bg-teal-600 hover:text-white transition-all">
                      <i className="fa-solid fa-pen-to-square text-xs"></i>
                    </button>
                    <button onClick={() => handleDelete(tenant.id)} className="w-9 h-9 flex items-center justify-center bg-rose-50 text-rose-500 rounded-xl hover:bg-rose-500 hover:text-white transition-all">
                      <i className="fa-solid fa-trash text-xs"></i>
                    </button>
                  </div>
                </td>
              </tr>
            ))}
            {tenantList.length === 0 && (
              <tr>
                <td colSpan={4} className="py-20 text-center text-slate-400 font-black uppercase text-[10px] tracking-[0.2em]">
                   Ma jiraan macmiil la helay
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setIsModalOpen(false)}></div>
          <div className="bg-white rounded-[2rem] w-full max-w-xl relative z-10 shadow-2xl animate-in zoom-in duration-300 overflow-hidden border border-slate-100">
            <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/30">
              <h2 className="text-2xl font-black text-slate-900 tracking-tight">
                {editingTenant ? 'Bedel Macmiilka' : 'Kudar Macmiil Cusub'}
              </h2>
              <button onClick={() => setIsModalOpen(false)} className="w-10 h-10 rounded-full hover:bg-white flex items-center justify-center text-slate-400 transition-colors shadow-sm">
                <i className="fa-solid fa-xmark text-xl"></i>
              </button>
            </div>
            <form onSubmit={handleSubmit} className="p-8 space-y-6">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Full Name</label>
                <input required value={formData.name} onChange={(e) => setFormData({ ...formData, name: e.target.value })} className="w-full px-5 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl text-sm font-semibold focus:ring-2 focus:ring-teal-500 outline-none transition-all" placeholder="Gali magaca oo buuxa" />
              </div>
              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Building</label>
                  <select required value={formData.propertyId} onChange={(e) => setFormData({ ...formData, propertyId: e.target.value })} className="w-full px-5 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl text-sm font-semibold focus:ring-2 focus:ring-teal-500 outline-none">
                    {properties.map(p => <option key={p.id} value={p.id}>{p.name} ({p.type})</option>)}
                    {properties.length === 0 && <option value="">No properties available</option>}
                  </select>
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Unit Number</label>
                  <input required value={formData.unit} onChange={(e) => setFormData({ ...formData, unit: e.target.value })} className="w-full px-5 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl text-sm font-semibold focus:ring-2 focus:ring-teal-500 outline-none" placeholder="e.g. 4B or Room 10" />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Phone Number</label>
                  <input required value={formData.phone} onChange={(e) => setFormData({ ...formData, phone: e.target.value })} className="w-full px-5 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl text-sm font-semibold focus:ring-2 focus:ring-teal-500 outline-none" placeholder="252..." />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Email</label>
                  <input required type="email" value={formData.email} onChange={(e) => setFormData({ ...formData, email: e.target.value })} className="w-full px-5 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl text-sm font-semibold focus:ring-2 focus:ring-teal-500 outline-none" placeholder="macmiil@elite.so" />
                </div>
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Status</label>
                <div className="flex p-1.5 bg-slate-100 rounded-2xl gap-1">
                  {(['Active', 'Ending Soon', 'Past Due'] as const).map(s => (
                    <button 
                      key={s} 
                      type="button" 
                      onClick={() => setFormData({ ...formData, status: s })} 
                      className={`flex-1 py-2.5 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all ${formData.status === s ? 'bg-white text-teal-600 shadow-sm' : 'text-slate-400'}`}
                    >
                      {s}
                    </button>
                  ))}
                </div>
              </div>
              <button type="submit" className="w-full py-5 bg-teal-600 text-white rounded-2xl font-black text-sm shadow-xl shadow-teal-600/20 hover:bg-teal-700 transition-all flex items-center justify-center gap-3 active:scale-[0.98]">
                <i className="fa-solid fa-cloud-arrow-up"></i>
                {editingTenant ? 'KEYDI ISBADALKA' : 'DHAMAYSTIR MACMIILKA'}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Tenants;

