import { Property, Tenant, MaintenanceRequest, Sale, RentRecord, FinancialRecord } from './types';
import * as mock from './mockData';

const BASE_URL = 'http://localhost:5000/api';

class ApiService {
  private getLocal<T>(key: string, fallback: T[]): T[] {
    try {
      const data = localStorage.getItem(`eliteestate_${key}`);
      return data ? JSON.parse(data) : fallback;
    } catch (e) { return fallback; }
  }

  private setLocal<T>(key: string, data: T[]): void {
    try { localStorage.setItem(`eliteestate_${key}`, JSON.stringify(data)); } catch (e) {}
  }

  // Improved safeRequest to handle PUT and DELETE fallbacks
  private async safeRequest<T>(endpoint: string, method: string, localKey: string, fallback: any, body?: any): Promise<T> {
    try {
      const response = await fetch(`${BASE_URL}${endpoint}`, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: body ? JSON.stringify(body) : undefined,
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const data = await response.json();
      return data;
    } catch (error) {
      console.error(`Fetch error for ${endpoint} (${method}):`, error);
      // Fallback to local data
      if (method === 'GET') {
        return this.getLocal<T>(localKey, fallback) as T;
      } else if (method === 'POST') {
        const localData = this.getLocal<T>(localKey, fallback) as T[];
        const newItem = { ...body, id: localData.length + 1 };
        this.setLocal(localKey, [...localData, newItem]);
        return newItem as T;
      } else if (method === 'PUT') {
        const localData = this.getLocal<T>(localKey, fallback) as T[];
        const updatedData = localData.map(item => (item as any).id === body.id ? { ...item, ...body } : item);
        this.setLocal(localKey, updatedData);
        return body as T;
      } else if (method === 'DELETE') {
        const localData = this.getLocal<T>(localKey, fallback) as T[];
        const filteredData = localData.filter(item => (item as any).id !== body.id);
        this.setLocal(localKey, filteredData);
        return body as T;
      } else {
        return fallback; // Or throw the error, depending on desired behavior
      }
    }
  }

  async getProperties(): Promise<Property[]> {
    return this.safeRequest<Property[]>('/properties', 'GET', 'properties', mock.properties);
  }

  async createProperty(property: Partial<Property>): Promise<Property> {
    return this.safeRequest<Property>('/properties', 'POST', 'properties', {}, property);
  }

  async updateProperty(property: Property): Promise<Property> {
    return this.safeRequest<Property>(`/properties/${property.id}`, 'PUT', 'properties', {}, property);
  }

  async deleteProperty(id: number): Promise<Property> {
    return this.safeRequest<Property>(`/properties/${id}`, 'DELETE', 'properties', { id: -1 }, { id });
  }

  async getTenants(): Promise<Tenant[]> {
    return this.safeRequest<Tenant[]>('/tenants', 'GET', 'tenants', mock.tenants);
  }

  async createTenant(tenant: Partial<Tenant>): Promise<Tenant> {
    return this.safeRequest<Tenant>('/tenants', 'POST', 'tenants', {}, tenant);
  }

  async updateTenant(tenant: Tenant): Promise<Tenant> {
    return this.safeRequest<Tenant>(`/tenants/${tenant.id}`, 'PUT', 'tenants', {}, tenant);
  }



**Refining API Integration**

